{
  "name": "SQL Vision",
  "description": "A visual interpreter for complex SQL queries. Analyze nested structures, separate SELECT units, and inspect their ASTs using Gemini AI."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface AstDetails {
  columns: string[];
  sources: string[]; // Tables or other subqueries
  joins: string[];
  conditions: string[]; // Where/Having clauses
  groupBy?: string[];
  orderBy?: string[];
}

export interface SqlNode {
  id: string;
  label: string; // Short name e.g. "Main Query", "Subquery A"
  type: 'ROOT' | 'SUBQUERY' | 'CTE' | 'UNION' | 'JOIN_PART';
  sqlSnippet: string;
  explanation: string;
  parentId?: string | null; // For tree construction
  ast: AstDetails;
}

export interface AnalysisResult {
  nodes: SqlNode[];
}

export enum QueryStatus {
  IDLE = 'IDLE',
  LOADING = 'LOADING',
  SUCCESS = 'SUCCESS',
  ERROR = 'ERROR'
}

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const SYSTEM_INSTRUCTION = `
You are an expert SQL parser and visualizer backend. 
Your task is to take a raw SQL query (which may vary in dialect) and break it down into a hierarchical structure of logical units.
1. Identify the Main Query (Root).
2. Identify all Subqueries, CTEs (Common Table Expressions), and major logical blocks.
3. For EACH block, extract its specific "AST" details (columns selected, tables/sources used, join conditions, where clauses).
4. Create a parent-child relationship where the "Parent" is the query that USES the "Child" (e.g., Main Query uses Subquery A).
`;

export const analyzeSql = async (sql: string): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Analyze this SQL query structure:\n\n${sql}`,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            nodes: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING, description: "Unique ID like 'node_1'" },
                  label: { type: Type.STRING, description: "Human readable label like 'Main Select' or 'User CTE'" },
                  type: { type: Type.STRING, enum: ['ROOT', 'SUBQUERY', 'CTE', 'UNION', 'JOIN_PART'] },
                  sqlSnippet: { type: Type.STRING, description: "The specific SQL code for this block only" },
                  explanation: { type: Type.STRING, description: "Brief explanation of what this block does" },
                  parentId: { type: Type.STRING, description: "ID of the parent node that uses this query. Null if Root.", nullable: true },
                  ast: {
                    type: Type.OBJECT,
                    properties: {
                      columns: { type: Type.ARRAY, items: { type: Type.STRING } },
                      sources: { type: Type.ARRAY, items: { type: Type.STRING } },
                      joins: { type: Type.ARRAY, items: { type: Type.STRING } },
                      conditions: { type: Type.ARRAY, items: { type: Type.STRING } },
                      groupBy: { type: Type.ARRAY, items: { type: Type.STRING } },
                      orderBy: { type: Type.ARRAY, items: { type: Type.STRING } },
                    },
                    required: ["columns", "sources", "joins", "conditions"]
                  }
                },
                required: ["id", "label", "type", "sqlSnippet", "explanation", "ast"]
              }
            }
          },
          required: ["nodes"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as AnalysisResult;

  } catch (error) {
    console.error("Gemini Analysis Failed:", error);
    throw error;
  }
};

import React, { useEffect, useRef, useState } from 'react';
import * as d3 from 'd3';
import { SqlNode } from '../types';

interface QueryVisualizerProps {
  nodes: SqlNode[];
  onNodeSelect: (node: SqlNode) => void;
  selectedNodeId?: string;
}

interface TreeData extends SqlNode {
  children?: TreeData[];
}

export const QueryVisualizer: React.FC<QueryVisualizerProps> = ({ nodes, onNodeSelect, selectedNodeId }) => {
  const svgRef = useRef<SVGSVGElement>(null);
  const wrapperRef = useRef<HTMLDivElement>(null);
  const [dimensions, setDimensions] = useState({ width: 800, height: 600 });

  // Handle Resize
  useEffect(() => {
    const handleResize = () => {
      if (wrapperRef.current) {
        const { width, height } = wrapperRef.current.getBoundingClientRect();
        setDimensions({ width, height });
      }
    };
    window.addEventListener('resize', handleResize);
    handleResize(); // Initial
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  useEffect(() => {
    if (!nodes.length || !svgRef.current) return;

    // Clear previous render
    const svg = d3.select(svgRef.current);
    svg.selectAll("*").remove();

    // 1. Transform flat nodes to hierarchy
    // We handle the case where parentId references might be missing or circular gracefully
    const dataMap = new Map<string, TreeData>();
    nodes.forEach(node => dataMap.set(node.id, { ...node, children: [] }));

    let rootNode: TreeData | null = null;

    nodes.forEach(node => {
      if (node.parentId && dataMap.has(node.parentId)) {
        dataMap.get(node.parentId)!.children!.push(dataMap.get(node.id)!);
      } else {
        // If no parent, or parent not found, treat as a potential root
        // If multiple roots exist (rare in valid SQL parse), we pick the one explicitly marked ROOT or the first one.
        if (!rootNode || node.type === 'ROOT') {
          rootNode = dataMap.get(node.id)!;
        }
      }
    });

    if (!rootNode) return;

    // 2. Setup D3 Tree
    const { width, height } = dimensions;
    const margin = { top: 40, right: 90, bottom: 40, left: 90 };
    const innerWidth = width - margin.left - margin.right;
    const innerHeight = height - margin.top - margin.bottom;

    const hierarchy = d3.hierarchy<TreeData>(rootNode);

    // Use a tree layout
    const treeLayout = d3.tree<TreeData>().size([innerHeight, innerWidth]); // Swap for horizontal layout
    const root = treeLayout(hierarchy);

    const g = svg.append("g")
      .attr("transform", `translate(${margin.left},${margin.top})`);

    // Links
    g.selectAll(".link")
      .data(root.links())
      .enter().append("path")
      .attr("class", "link")
      .attr("fill", "none")
      .attr("stroke", "#4b5563")
      .attr("stroke-width", 2)
      .attr("d", d3.linkHorizontal()
        .x(d => d.y)
        .y(d => d.x) as any
      );

    // Nodes
    const nodeGroup = g.selectAll(".node")
      .data(root.descendants())
      .enter().append("g")
      .attr("class", "node")
      .attr("transform", d => `translate(${d.y},${d.x})`)
      .style("cursor", "pointer")
      .on("click", (event, d) => {
        onNodeSelect(d.data);
      });

    // Node Circles
    nodeGroup.append("circle")
      .attr("r", 15)
      .attr("fill", d => {
        if (d.data.id === selectedNodeId) return "#3b82f6"; // Blue if selected
        return d.data.type === 'ROOT' ? "#ef4444" : "#10b981"; // Red root, Green others
      })
      .attr("stroke", "#fff")
      .attr("stroke-width", 2);

    // Labels
    nodeGroup.append("text")
      .attr("dy", -25) // Move text above the node
      .attr("text-anchor", "middle") 
      .text(d => d.data.label)
      .style("font-size", "14px")
      .style("fill", "#e5e7eb") // Light gray
      .style("font-weight", "bold")
      .style("text-shadow", "0px 1px 2px black");

    // Type Labels
    nodeGroup.append("text")
        .attr("dy", 25)
        .attr("text-anchor", "middle")
        .text(d => d.data.type)
        .style("font-size", "10px")
        .style("fill", "#9ca3af");

    // Add zoom capabilities
    const zoom = d3.zoom<SVGSVGElement, unknown>()
      .scaleExtent([0.1, 3])
      .on("zoom", (event) => {
        g.attr("transform", event.transform);
      });

    svg.call(zoom);
    // Center the tree initially
    const initialTransform = d3.zoomIdentity
      .translate(margin.left, margin.top)
      .scale(1);
    svg.call(zoom.transform, initialTransform);

  }, [nodes, dimensions, selectedNodeId, onNodeSelect]);

  return (
    <div ref={wrapperRef} className="w-full h-full bg-gray-900 rounded-lg overflow-hidden border border-gray-800 shadow-inner relative">
      <div className="absolute top-2 left-2 text-xs text-gray-500 pointer-events-none">
        Drag to pan, Scroll to zoom
      </div>
      <svg ref={svgRef} width="100%" height="100%"></svg>
    </div>
  );
};

import React from 'react';
import { SqlNode } from '../types';

interface AstInspectorProps {
  node: SqlNode | null;
}

const DetailSection: React.FC<{ title: string; items?: string[] }> = ({ title, items }) => {
  if (!items || items.length === 0) return null;
  return (
    <div className="mb-4">
      <h4 className="text-xs uppercase tracking-wider text-gray-500 font-bold mb-2">{title}</h4>
      <div className="flex flex-wrap gap-2">
        {items.map((item, idx) => (
          <span key={idx} className="px-2 py-1 bg-gray-800 border border-gray-700 rounded text-sm text-blue-200 font-mono break-all">
            {item}
          </span>
        ))}
      </div>
    </div>
  );
};

export const AstInspector: React.FC<AstInspectorProps> = ({ node }) => {
  if (!node) {
    return (
      <div className="h-full flex items-center justify-center text-gray-500 p-8 text-center border-l border-gray-800">
        <p>Select a node in the graph to view its Abstract Syntax Tree (AST).</p>
      </div>
    );
  }

  return (
    <div className="h-full flex flex-col bg-gray-900 border-l border-gray-800 overflow-hidden">
      {/* Header */}
      <div className="p-4 border-b border-gray-800 bg-gray-800/50">
        <div className="flex items-center justify-between mb-1">
          <span className={`px-2 py-0.5 rounded text-xs font-bold ${node.type === 'ROOT' ? 'bg-red-900 text-red-200' : 'bg-green-900 text-green-200'}`}>
            {node.type}
          </span>
          <span className="text-gray-500 text-xs font-mono">{node.id}</span>
        </div>
        <h2 className="text-xl font-bold text-white mb-2">{node.label}</h2>
        <p className="text-sm text-gray-400">{node.explanation}</p>
      </div>

      {/* Content */}
      <div className="flex-1 overflow-y-auto p-4 custom-scrollbar">

        {/* SQL Snippet Preview */}
        <div className="mb-6">
          <h4 className="text-xs uppercase tracking-wider text-gray-500 font-bold mb-2">SQL Snippet</h4>
          <pre className="bg-black/30 p-3 rounded text-sm font-mono text-yellow-100 overflow-x-auto border border-gray-800">
            <code>{node.sqlSnippet}</code>
          </pre>
        </div>

        {/* AST details */}
        <div className="space-y-6">
          <DetailSection title="Projections (Columns)" items={node.ast.columns} />
          <DetailSection title="Sources (Tables)" items={node.ast.sources} />
          <DetailSection title="Joins" items={node.ast.joins} />
          <DetailSection title="Conditions (Where/Having)" items={node.ast.conditions} />
          <DetailSection title="Group By" items={node.ast.groupBy} />
          <DetailSection title="Order By" items={node.ast.orderBy} />
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { analyzeSql } from './services/geminiService';
import { AnalysisResult, QueryStatus, SqlNode } from './types';
import { QueryVisualizer } from './components/QueryVisualizer';
import { AstInspector } from './components/AstInspector';

// Example complex query for initial state
const DEFAULT_QUERY = `
WITH RegionalSales AS (
    SELECT region, SUM(amount) as total_sales
    FROM sales
    JOIN locations ON sales.location_id = locations.id
    WHERE sales.date > '2023-01-01'
    GROUP BY region
),
TopRegions AS (
    SELECT region
    FROM RegionalSales
    WHERE total_sales > 1000000
)
SELECT 
    e.employee_name,
    r.region,
    COUNT(o.id) as order_count
FROM employees e
JOIN orders o ON e.id = o.employee_id
JOIN TopRegions r ON e.region = r.region
WHERE o.status = 'completed'
GROUP BY e.employee_name, r.region
ORDER BY order_count DESC;
`;

const App: React.FC = () => {
  const [sqlInput, setSqlInput] = useState<string>(DEFAULT_QUERY.trim());
  const [status, setStatus] = useState<QueryStatus>(QueryStatus.IDLE);
  const [data, setData] = useState<AnalysisResult | null>(null);
  const [selectedNode, setSelectedNode] = useState<SqlNode | null>(null);
  const [errorMsg, setErrorMsg] = useState<string>("");

  const handleAnalyze = async () => {
    if (!sqlInput.trim()) return;

    setStatus(QueryStatus.LOADING);
    setErrorMsg("");
    setSelectedNode(null);

    try {
      const result = await analyzeSql(sqlInput);
      setData(result);
      // Auto-select the root node if available
      const root = result.nodes.find(n => n.type === 'ROOT');
      if (root) setSelectedNode(root);
      setStatus(QueryStatus.SUCCESS);
    } catch (err: any) {
      console.error(err);
      setErrorMsg(err.message || "Failed to analyze SQL. Please check your API key or input.");
      setStatus(QueryStatus.ERROR);
    }
  };

  return (
    <div className="flex h-screen w-full bg-gray-950 text-gray-200 font-sans">
      {/* Sidebar: Input */}
      <div className="w-1/3 min-w-[350px] max-w-[500px] flex flex-col border-r border-gray-800 bg-gray-900/50">
        <div className="p-4 border-b border-gray-800 flex justify-between items-center bg-gray-900">
          <div className="flex items-center gap-2">
            <div className="w-3 h-3 rounded-full bg-blue-500"></div>
            <h1 className="text-lg font-bold text-white tracking-tight">SQL Vision</h1>
          </div>
          <button 
            onClick={handleAnalyze}
            disabled={status === QueryStatus.LOADING}
            className={`px-4 py-1.5 rounded text-sm font-semibold transition-all ${
              status === QueryStatus.LOADING 
              ? 'bg-blue-900 text-blue-300 cursor-wait' 
              : 'bg-blue-600 hover:bg-blue-500 text-white shadow-lg shadow-blue-900/20'
            }`}
          >
            {status === QueryStatus.LOADING ? 'Analyzing...' : 'Visualize'}
          </button>
        </div>

        <div className="flex-1 relative group">
          <textarea 
            value={sqlInput}
            onChange={(e) => setSqlInput(e.target.value)}
            className="w-full h-full p-4 bg-gray-950 text-gray-300 font-mono text-sm resize-none focus:outline-none focus:ring-1 focus:ring-blue-500/50"
            spellCheck={false}
            placeholder="Paste your complex SQL query here..."
          />
        </div>

        {status === QueryStatus.ERROR && (
          <div className="p-4 bg-red-900/20 border-t border-red-900/50 text-red-200 text-sm">
            <strong>Error:</strong> {errorMsg}
          </div>
        )}
      </div>

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col relative">
        {/* Graph Area */}
        <div className="flex-1 relative bg-black">
          {data ? (
            <QueryVisualizer 
              nodes={data.nodes} 
              onNodeSelect={setSelectedNode}
              selectedNodeId={selectedNode?.id}
            />
          ) : (
             <div className="absolute inset-0 flex flex-col items-center justify-center text-gray-600">
               {status === QueryStatus.LOADING ? (
                 <div className="animate-pulse flex flex-col items-center">
                   <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mb-4"></div>
                   <p>Processing AST with Gemini AI...</p>
                 </div>
               ) : (
                 <>
                   <svg className="w-24 h-24 mb-4 opacity-20" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19.428 15.428a2 2 0 00-1.022-.547l-2.384-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z"></path></svg>
                   <p>Enter a query and click Visualize to generate the Query Map.</p>
                 </>
               )}
             </div>
          )}
        </div>
      </div>

      {/* Right Sidebar: Inspector */}
      <div className="w-96 border-l border-gray-800 bg-gray-900 z-10 shadow-xl">
        <AstInspector node={selectedNode} />
      </div>
    </div>
  );
};

export default App;

export interface AstDetails {
  columns: string[];
  sources: string[]; // Tables or other subqueries
  joins: string[];
  conditions: string[]; // Where/Having clauses
  groupBy?: string[];
  orderBy?: string[];
}

export interface SqlNode {
  id: string;
  label: string; // Short name e.g. "Main Query", "Subquery A"
  type: 'ROOT' | 'CTE_BLOCK' | 'CTE' | 'MAIN_QUERY' | 'SUBQUERY' | 'UNION' | 'JOIN_PART';
  sqlSnippet: string;
  explanation: string;
  parentId?: string | null; // For tree construction
  ast: AstDetails;
}

export interface AnalysisResult {
  nodes: SqlNode[];
