import React, { useState, useEffect, useRef } from 'react';
import { analyzeSql } from './services/geminiService';
import { AnalysisResult, QueryStatus, SqlNode } from './types';
import { QueryVisualizer } from './components/QueryVisualizer';
import { AstInspector } from './components/AstInspector';

// Example complex query for initial state
const DEFAULT_QUERY = `
WITH RegionalSales AS (
    SELECT region, SUM(amount) as total_sales
    FROM sales
    JOIN locations ON sales.location_id = locations.id
    WHERE sales.date > '2023-01-01'
    GROUP BY region
),
TopRegions AS (
    SELECT region
    FROM RegionalSales
    WHERE total_sales > 1000000
)
SELECT 
    e.employee_name,
    r.region,
    COUNT(o.id) as order_count
FROM employees e
JOIN orders o ON e.id = o.employee_id
JOIN TopRegions r ON e.region = r.region
WHERE o.status = 'completed'
GROUP BY e.employee_name, r.region
ORDER BY order_count DESC;
`;

const App: React.FC = () => {
  const [sqlInput, setSqlInput] = useState<string>(DEFAULT_QUERY.trim());
  const [status, setStatus] = useState<QueryStatus>(QueryStatus.IDLE);
  const [data, setData] = useState<AnalysisResult | null>(null);
  const [selectedNode, setSelectedNode] = useState<SqlNode | null>(null);
  const [errorMsg, setErrorMsg] = useState<string>("");

  // Layout State
  const [sidebarWidth, setSidebarWidth] = useState(400);
  const [inspectorWidth, setInspectorWidth] = useState(380);
  const [isResizingSidebar, setIsResizingSidebar] = useState(false);
  const [isResizingInspector, setIsResizingInspector] = useState(false);

  // Resize Handlers
  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (isResizingSidebar) {
        setSidebarWidth(Math.max(250, Math.min(600, e.clientX)));
      }
      if (isResizingInspector) {
        setInspectorWidth(Math.max(300, Math.min(600, window.innerWidth - e.clientX)));
      }
    };

    const handleMouseUp = () => {
      setIsResizingSidebar(false);
      setIsResizingInspector(false);
      document.body.style.cursor = 'default';
    };

    if (isResizingSidebar || isResizingInspector) {
      document.addEventListener('mousemove', handleMouseMove);
      document.addEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = 'col-resize';
    }

    return () => {
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = 'default';
    };
  }, [isResizingSidebar, isResizingInspector]);

  const handleAnalyze = async () => {
    if (!sqlInput.trim()) return;

    setStatus(QueryStatus.LOADING);
    setErrorMsg("");
    setSelectedNode(null);

    try {
      const result = await analyzeSql(sqlInput);
      setData(result);
      const root = result.nodes.find(n => n.type === 'ROOT');
      if (root) setSelectedNode(root);
      setStatus(QueryStatus.SUCCESS);
    } catch (err: any) {
      console.error(err);
      setErrorMsg(err.message || "Failed to analyze SQL. Please check your API key or input.");
      setStatus(QueryStatus.ERROR);
    }
  };

  return (
    <div className="flex h-screen w-full bg-white text-gray-900 font-sans overflow-hidden">

      {/* Sidebar: Input (Resizable) */}
      <div 
        style={{ width: sidebarWidth }} 
        className="flex-shrink-0 flex flex-col border-r border-gray-200 bg-gray-50"
      >
        <div className="p-4 border-b border-gray-200 flex justify-between items-center bg-white">
          <div className="flex items-center gap-2">
            <div className="w-3 h-3 rounded-full bg-blue-600"></div>
            <h1 className="text-lg font-bold text-gray-800 tracking-tight">SQL Vision</h1>
          </div>
          <button 
            onClick={handleAnalyze}
            disabled={status === QueryStatus.LOADING}
            className={`px-4 py-1.5 rounded text-sm font-semibold transition-all shadow-sm ${
              status === QueryStatus.LOADING 
              ? 'bg-blue-100 text-blue-800 cursor-wait' 
              : 'bg-blue-600 hover:bg-blue-700 text-white shadow-blue-500/20'
            }`}
          >
            {status === QueryStatus.LOADING ? 'Analyzing...' : 'Visualize'}
          </button>
        </div>

        {/* Code Input (Kept Dark) */}
        <div className="flex-1 relative group">
          <textarea 
            value={sqlInput}
            onChange={(e) => setSqlInput(e.target.value)}
            className="w-full h-full p-4 bg-gray-900 text-gray-300 font-mono text-sm resize-none focus:outline-none focus:ring-inset focus:ring-2 focus:ring-blue-500/50"
            spellCheck={false}
            placeholder="Paste your complex SQL query here..."
          />
        </div>

        {status === QueryStatus.ERROR && (
          <div className="p-4 bg-red-50 border-t border-red-200 text-red-700 text-sm">
            <strong>Error:</strong> {errorMsg}
          </div>
        )}
      </div>

      {/* Resizer Handle Left */}
      <div 
        className="w-1 cursor-col-resize hover:bg-blue-400 bg-gray-200 transition-colors z-20 flex-shrink-0"
        onMouseDown={() => setIsResizingSidebar(true)}
      />

      {/* Main Content Area (Light Mode) */}
      <div className="flex-1 flex flex-col relative bg-gray-50 overflow-hidden">
        {/* Graph Area */}
        <div className="flex-1 relative">
          {data ? (
            <QueryVisualizer 
              nodes={data.nodes} 
              onNodeSelect={setSelectedNode}
              selectedNodeId={selectedNode?.id}
            />
          ) : (
             <div className="absolute inset-0 flex flex-col items-center justify-center text-gray-400">
               {status === QueryStatus.LOADING ? (
                 <div className="flex flex-col items-center">
                   <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mb-4"></div>
                   <p className="text-gray-600 font-medium">Processing AST with Gemini AI...</p>
                 </div>
               ) : (
                 <>
                   <svg className="w-24 h-24 mb-4 opacity-10 text-gray-900" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19.428 15.428a2 2 0 00-1.022-.547l-2.384-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z"></path></svg>
                   <p className="text-gray-500">Enter a query and click Visualize to generate the Query Map.</p>
                 </>
               )}
             </div>
          )}
        </div>
      </div>

      {/* Resizer Handle Right */}
      <div 
        className="w-1 cursor-col-resize hover:bg-blue-400 bg-gray-200 transition-colors z-20 flex-shrink-0"
        onMouseDown={() => setIsResizingInspector(true)}
      />

      {/* Right Sidebar: Inspector (Resizable, Light Mode) */}
      <div 
        style={{ width: inspectorWidth }} 
        className="flex-shrink-0 border-l border-gray-200 bg-white z-10 shadow-xl"
      >
        <AstInspector node={selectedNode} />
      </div>
    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState } from 'react';
import * as d3 from 'd3';
import { SqlNode } from '../types';

interface QueryVisualizerProps {
  nodes: SqlNode[];
  onNodeSelect: (node: SqlNode) => void;
  selectedNodeId?: string;
}

interface TreeData extends SqlNode {
  children?: TreeData[];
}

export const QueryVisualizer: React.FC<QueryVisualizerProps> = ({ nodes, onNodeSelect, selectedNodeId }) => {
  const svgRef = useRef<SVGSVGElement>(null);
  const wrapperRef = useRef<HTMLDivElement>(null);
  const [dimensions, setDimensions] = useState({ width: 800, height: 600 });

  useEffect(() => {
    const handleResize = () => {
      if (wrapperRef.current) {
        const { width, height } = wrapperRef.current.getBoundingClientRect();
        setDimensions({ width, height });
      }
    };
    window.addEventListener('resize', handleResize);
    handleResize(); 
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  useEffect(() => {
    if (!nodes.length || !svgRef.current) return;

    const svg = d3.select(svgRef.current);
    svg.selectAll("*").remove();

    // --- Data Preparation ---
    const dataMap = new Map<string, TreeData>();
    nodes.forEach(node => dataMap.set(node.id, { ...node, children: [] }));

    let rootNode: TreeData | null = null;
    nodes.forEach(node => {
      if (node.parentId && dataMap.has(node.parentId)) {
        dataMap.get(node.parentId)!.children!.push(dataMap.get(node.id)!);
      } else {
        if (!rootNode || node.type === 'ROOT') {
          rootNode = dataMap.get(node.id)!;
        }
      }
    });

    if (!rootNode) return;

    // --- Configuration ---
    const nodeWidth = 240;
    const nodeHeight = 90;
    const horizontalSpacing = 60;
    const verticalSpacing = 100;

    // --- Tree Layout (Vertical) ---
    const hierarchy = d3.hierarchy<TreeData>(rootNode);

    // nodeSize: [width, height] for vertical trees usually corresponds to [horizontal_space, vertical_space]
    // But d3.tree().nodeSize([x, y]) where x is dimension along the breadth (siblings) and y is depth.
    // In a vertical tree: x is horizontal coordinate, y is vertical coordinate.
    const treeLayout = d3.tree<TreeData>()
      .nodeSize([nodeWidth + horizontalSpacing, nodeHeight + verticalSpacing])
      .separation((a, b) => a.parent === b.parent ? 1.1 : 1.3);

    const root = treeLayout(hierarchy);

    // --- Zoom & Pan Setup ---
    const g = svg.append("g");

    const zoom = d3.zoom<SVGSVGElement, unknown>()
      .scaleExtent([0.1, 2])
      .on("zoom", (event) => {
        g.attr("transform", event.transform);
      });

    svg.call(zoom);

    // --- Grid Background (Dot Pattern) ---
    const defs = svg.append("defs");
    const pattern = defs.append("pattern")
        .attr("id", "grid")
        .attr("width", 20)
        .attr("height", 20)
        .attr("patternUnits", "userSpaceOnUse");
    pattern.append("circle")
        .attr("cx", 2)
        .attr("cy", 2)
        .attr("r", 1)
        .attr("fill", "#e5e7eb"); // Gray-200 dots

    svg.append("rect")
       .attr("width", "100%")
       .attr("height", "100%")
       .attr("fill", "url(#grid)")
       .style("pointer-events", "none"); // Let zoom events pass through

    // --- Draw Links (Vertical) ---
    g.selectAll(".link")
      .data(root.links())
      .enter().append("path")
      .attr("class", "link")
      .attr("fill", "none")
      .attr("stroke", "#9ca3af") // Gray-400
      .attr("stroke-width", 2)
      .attr("d", d3.linkVertical() // Vertical link generator
        .x(d => d.x)
        .y(d => d.y) as any
      );

    // --- Draw Nodes ---
    const nodeGroup = g.selectAll(".node")
      .data(root.descendants())
      .enter().append("g")
      .attr("class", "node")
      .attr("transform", d => `translate(${d.x},${d.y})`) // Vertical: x is horiz, y is vert
      .style("cursor", "pointer")
      .on("click", (event, d) => {
        onNodeSelect(d.data);
      });

    // 1. Node Card Background (Rect) - Light Theme
    nodeGroup.append("rect")
      .attr("width", nodeWidth)
      .attr("height", nodeHeight)
      .attr("x", -nodeWidth / 2) // Center horizontally
      .attr("y", 0) 
      .attr("rx", 8)
      .attr("fill", "#ffffff") // White background
      .attr("stroke", d => {
        if (d.data.id === selectedNodeId) return "#2563eb"; // Blue-600 selected
        // Color by Type
        switch (d.data.type) {
          case 'ROOT': return "#dc2626"; // Red
          case 'CTE': return "#9333ea"; // Purple
          case 'MAIN_QUERY': return "#059669"; // Emerald
          case 'SUBQUERY': return "#d97706"; // Amber
          default: return "#4b5563"; // Gray
        }
      })
      .attr("stroke-width", d => d.data.id === selectedNodeId ? 3 : 2)
      .style("filter", "drop-shadow(0px 2px 4px rgba(0,0,0,0.1))");

    // 2. Node Type Label (Badge)
    nodeGroup.append("rect")
      .attr("x", -nodeWidth / 2 + 10)
      .attr("y", 12)
      .attr("width", d => d.data.type.length * 7 + 10) 
      .attr("height", 18)
      .attr("rx", 4)
      .attr("fill", d => {
         switch (d.data.type) {
          case 'ROOT': return "#fef2f2"; // Red-50
          case 'CTE': return "#faf5ff"; // Purple-50
          case 'MAIN_QUERY': return "#ecfdf5"; // Emerald-50
          case 'SUBQUERY': return "#fffbeb"; // Amber-50
          default: return "#f3f4f6"; 
        }
      });

    nodeGroup.append("text")
      .attr("x", -nodeWidth / 2 + 15)
      .attr("y", 24)
      .text(d => d.data.type)
      .style("font-size", "10px")
      .style("font-weight", "bold")
      .style("fill", d => {
         switch (d.data.type) {
          case 'ROOT': return "#b91c1c"; 
          case 'CTE': return "#7e22ce"; 
          case 'MAIN_QUERY': return "#047857"; 
          case 'SUBQUERY': return "#b45309"; 
          default: return "#374151"; 
        }
      });

    // 3. Main Label
    nodeGroup.append("text")
      .attr("x", -nodeWidth / 2 + 12)
      .attr("y", 48) 
      .text(d => {
        const str = d.data.label;
        return str.length > 25 ? str.substring(0, 25) + "..." : str;
      })
      .style("font-size", "14px")
      .style("font-weight", "bold")
      .style("fill", "#111827"); // Gray-900

    // 4. Short Snippet preview (Explanation)
    nodeGroup.append("text")
      .attr("x", -nodeWidth / 2 + 12)
      .attr("y", 68)
      .text(d => {
         const str = d.data.explanation || "";
         return str.length > 35 ? str.substring(0, 35) + "..." : str;
      })
      .style("font-size", "11px")
      .style("fill", "#6b7280"); // Gray-500

    // --- Initial Zoom to Fit/Center ---
    let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
    root.descendants().forEach(d => {
      minX = Math.min(minX, d.x - nodeWidth/2);
      maxX = Math.max(maxX, d.x + nodeWidth/2);
      minY = Math.min(minY, d.y);
      maxY = Math.max(maxY, d.y + nodeHeight);
    });

    const treeWidth = maxX - minX;
    const treeHeight = maxY - minY;

    const scale = Math.min(
      1.2, 
      Math.min(
        (dimensions.width - 100) / treeWidth,
        (dimensions.height - 100) / treeHeight
      )
    );

    const initialTransform = d3.zoomIdentity
      .translate(
        (dimensions.width - treeWidth * scale) / 2 - minX * scale, 
        (dimensions.height - treeHeight * scale) / 2 - minY * scale + 40
      )
      .scale(scale);

    svg.call(zoom.transform, initialTransform);

  }, [nodes, dimensions, selectedNodeId, onNodeSelect]);

  return (
    <div ref={wrapperRef} className="w-full h-full bg-gray-50 rounded-lg overflow-hidden relative border border-gray-200 shadow-inner">
      <div className="absolute top-4 left-4 text-xs text-gray-500 pointer-events-none z-10 flex flex-col gap-1 p-2 bg-white/80 rounded border border-gray-100 shadow-sm backdrop-blur-sm">
        <div className="flex items-center gap-2"><span className="w-3 h-3 rounded bg-purple-600"></span> CTE (Definition)</div>
        <div className="flex items-center gap-2"><span className="w-3 h-3 rounded bg-emerald-600"></span> Main Query</div>
        <div className="flex items-center gap-2"><span className="w-3 h-3 rounded bg-amber-600"></span> Subquery (Nested)</div>
      </div>
      <svg ref={svgRef} width="100%" height="100%"></svg>
    </div>
  );
};

