export const AstInspector: React.FC<AstInspectorProps> = ({ node }) => {
  if (!node) {
    return (
      <div className="h-full flex items-center justify-center text-gray-500 p-8 text-center bg-white">
        <p>Select a node in the graph to view its Abstract Syntax Tree (AST).</p>
      </div>
    );
  }

  const getTypeStyle = (type: string) => {
    switch (type) {
      case 'ROOT': return 'bg-red-100 text-red-800 border-red-200';
      case 'CTE': return 'bg-purple-100 text-purple-800 border-purple-200';
      case 'MAIN_QUERY': return 'bg-emerald-100 text-emerald-800 border-emerald-200';
      case 'SUBQUERY': return 'bg-amber-100 text-amber-800 border-amber-200';
      default: return 'bg-gray-100 text-gray-800 border-gray-200';
    }
  };

  return (
    <div className="h-full flex flex-col bg-white overflow-hidden">
      {/* Header */}
      <div className="p-4 border-b border-gray-200 bg-gray-50/50">
        <div className="flex items-center justify-between mb-2">
          <span className={`px-2 py-0.5 rounded text-xs font-bold border ${getTypeStyle(node.type)}`}>
            {node.type}
          </span>
          <span className="text-gray-400 text-xs font-mono">{node.id}</span>
        </div>
        <h2 className="text-lg font-bold text-gray-900 mb-2 leading-tight">{node.label}</h2>
        <p className="text-sm text-gray-600">{node.explanation}</p>
      </div>

      {/* Content */}
      <div className="flex-1 overflow-y-auto p-4 custom-scrollbar">

        {/* SQL Snippet Preview - Kept Dark as requested */}
        <div className="mb-6">
          <h4 className="text-xs uppercase tracking-wider text-gray-500 font-bold mb-2">SQL Snippet</h4>
          <pre className="bg-gray-900 p-3 rounded text-sm font-mono text-yellow-100 overflow-x-auto border border-gray-700 max-h-60 custom-scrollbar shadow-sm">
            <code>{node.sqlSnippet}</code>
          </pre>
        </div>

        {/* AST details */}
        <div className="space-y-6">
          <DetailSection title="Projections (Columns)" items={node.ast.columns} />
          <DetailSection title="Sources (Tables)" items={node.ast.sources} />
          <DetailSection title="Joins" items={node.ast.joins} />
          <DetailSection title="Conditions (Where/Having)" items={node.ast.conditions} />
          <DetailSection title="Group By" items={node.ast.groupBy} />
          <DetailSection title="Order By" items={node.ast.orderBy} />
        </div>
      </div>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const SYSTEM_INSTRUCTION = `
You are an expert SQL parser and visualizer backend. 
Your task is to analyze the SYNTACTIC structure of a SQL query and return a hierarchical tree of nodes.

**CRITICAL RULES FOR HIERARCHY:**
1. **Root Node**: Represents the entire SQL file/input.
2. **CTE Definitions**: If the query uses a WITH clause, each CTE (Common Table Expression) definition must be a DIRECT CHILD of the Root Node.
   - **IMPORTANT**: Even if "CTE_B" selects from "CTE_A", treat them as SIBLING definitions in the WITH block. Do NOT nest CTEs inside each other. They are parallel definitions.
3. **Main Query**: The primary SELECT/INSERT/UPDATE statement is a sibling of the CTEs (child of Root).
4. **Subqueries**: Any SELECT statement nested physically inside a FROM, JOIN, WHERE, HAVING, or Projection clause must be a CHILD of the node containing it.
   - Example: "SELECT * FROM (SELECT ...)" -> The inner SELECT is a child of the outer SELECT.
5. **Unions**: If parts are combined via UNION, they are children of the UNION parent.

**Output Schema Requirements:**
For each node, provide:
- **id**: Unique string.
- **label**: Short name (e.g., "CTE: RegionalSales", "Main Query", "Subquery in FROM").
- **type**: One of ['ROOT', 'CTE', 'MAIN_QUERY', 'SUBQUERY', 'UNION'].
- **parentId**: The ID of the syntactic container node.
- **sqlSnippet**: The EXACT character-for-character substring from the original SQL text corresponding to this block. It is CRITICAL to preserve whitespace, comments, and newlines exactly as they appear in the source so that it can be highlighted in the UI.
- **ast**: Extract key details: columns, sources (tables), joins, conditions.
`;

export const analyzeSql = async (sql: string): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Analyze this SQL query structure:\n\n${sql}`,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            nodes: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING, description: "Unique ID like 'node_1'" },
                  label: { type: Type.STRING, description: "Human readable label" },
                  type: { type: Type.STRING, enum: ['ROOT', 'CTE', 'MAIN_QUERY', 'SUBQUERY', 'UNION', 'JOIN_PART'] },
                  sqlSnippet: { type: Type.STRING, description: "The EXACT source code substring for this block" },
                  explanation: { type: Type.STRING, description: "Brief explanation of what this block does" },
                  parentId: { type: Type.STRING, description: "ID of the parent node. Null if Root.", nullable: true },
                  ast: {
                    type: Type.OBJECT,
                    properties: {
                      columns: { type: Type.ARRAY, items: { type: Type.STRING } },
                      sources: { type: Type.ARRAY, items: { type: Type.STRING } },
                      joins: { type: Type.ARRAY, items: { type: Type.STRING } },
                      conditions: { type: Type.ARRAY, items: { type: Type.STRING } },
                      groupBy: { type: Type.ARRAY, items: { type: Type.STRING } },
                      orderBy: { type: Type.ARRAY, items: { type: Type.STRING } },
                    },
                    required: ["columns", "sources", "joins", "conditions"]
                  }
                },
                required: ["id", "label", "type", "sqlSnippet", "explanation", "ast"]
              }
            }
          },
          required: ["nodes"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as AnalysisResult;

  } catch (error) {
    console.error("Gemini Analysis Failed:", error);
    throw error;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { analyzeSql } from './services/geminiService';
import { AnalysisResult, QueryStatus, SqlNode } from './types';
import { QueryVisualizer } from './components/QueryVisualizer';
import { AstInspector } from './components/AstInspector';

// Example complex query for initial state
const DEFAULT_QUERY = `
WITH RegionalSales AS (
    SELECT region, SUM(amount) as total_sales
    FROM sales
    JOIN locations ON sales.location_id = locations.id
    WHERE sales.date > '2023-01-01'
    GROUP BY region
),
TopRegions AS (
    SELECT region
    FROM RegionalSales
    WHERE total_sales > 1000000
)
SELECT 
    e.employee_name,
    r.region,
    COUNT(o.id) as order_count
FROM employees e
JOIN orders o ON e.id = o.employee_id
JOIN TopRegions r ON e.region = r.region
WHERE o.status = 'completed'
GROUP BY e.employee_name, r.region
ORDER BY order_count DESC;
`;

const App: React.FC = () => {
  const [sqlInput, setSqlInput] = useState<string>(DEFAULT_QUERY.trim());
  const [status, setStatus] = useState<QueryStatus>(QueryStatus.IDLE);
  const [data, setData] = useState<AnalysisResult | null>(null);
  const [selectedNode, setSelectedNode] = useState<SqlNode | null>(null);
  const [errorMsg, setErrorMsg] = useState<string>("");

  // Refs
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  // Layout State
  const [sidebarWidth, setSidebarWidth] = useState(400);
  const [inspectorWidth, setInspectorWidth] = useState(380);
  const [isResizingSidebar, setIsResizingSidebar] = useState(false);
  const [isResizingInspector, setIsResizingInspector] = useState(false);

  // Resize Handlers
  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (isResizingSidebar) {
        setSidebarWidth(Math.max(250, Math.min(600, e.clientX)));
      }
      if (isResizingInspector) {
        setInspectorWidth(Math.max(300, Math.min(600, window.innerWidth - e.clientX)));
      }
    };

    const handleMouseUp = () => {
      setIsResizingSidebar(false);
      setIsResizingInspector(false);
      document.body.style.cursor = 'default';
    };

    if (isResizingSidebar || isResizingInspector) {
      document.addEventListener('mousemove', handleMouseMove);
      document.addEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = 'col-resize';
    }

    return () => {
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = 'default';
    };
  }, [isResizingSidebar, isResizingInspector]);

  // Highlight Code Logic
  useEffect(() => {
    if (selectedNode && textareaRef.current) {
      const snippet = selectedNode.sqlSnippet;
      if (!snippet) return;

      // Try exact match
      let startIdx = sqlInput.indexOf(snippet);
      let length = snippet.length;

      // If not found, try trimmed match (sometimes LLM trims whitespace)
      if (startIdx === -1) {
        const trimmedSnippet = snippet.trim();
        startIdx = sqlInput.indexOf(trimmedSnippet);
        length = trimmedSnippet.length;
      }

      if (startIdx !== -1) {
        // Focus and Select
        textareaRef.current.focus();
        textareaRef.current.setSelectionRange(startIdx, startIdx + length);

        // Note: Browsers usually scroll to selection automatically on focus + select.
        // If not, we could calculate scrollHeight, but this is usually sufficient.
      }
    }
  }, [selectedNode]); // Only run when a different node is selected

  const handleAnalyze = async () => {
    if (!sqlInput.trim()) return;

    setStatus(QueryStatus.LOADING);
    setErrorMsg("");
    setSelectedNode(null);

    try {
      const result = await analyzeSql(sqlInput);
      setData(result);
      const root = result.nodes.find(n => n.type === 'ROOT');
      if (root) setSelectedNode(root);
      setStatus(QueryStatus.SUCCESS);
    } catch (err: any) {
      console.error(err);
      setErrorMsg(err.message || "Failed to analyze SQL. Please check your API key or input.");
      setStatus(QueryStatus.ERROR);
    }
  };

  return (
    <div className="flex h-screen w-full bg-white text-gray-900 font-sans overflow-hidden">

      {/* Sidebar: Input (Resizable) */}
      <div 
        style={{ width: sidebarWidth }} 
        className="flex-shrink-0 flex flex-col border-r border-gray-200 bg-gray-50"
      >
        <div className="p-4 border-b border-gray-200 flex justify-between items-center bg-white">
          <div className="flex items-center gap-2">
            <div className="w-3 h-3 rounded-full bg-blue-600"></div>
            <h1 className="text-lg font-bold text-gray-800 tracking-tight">SQL Vision</h1>
          </div>
          <button 
            onClick={handleAnalyze}
            disabled={status === QueryStatus.LOADING}
            className={`px-4 py-1.5 rounded text-sm font-semibold transition-all shadow-sm ${
              status === QueryStatus.LOADING 
              ? 'bg-blue-100 text-blue-800 cursor-wait' 
              : 'bg-blue-600 hover:bg-blue-700 text-white shadow-blue-500/20'
            }`}
          >
            {status === QueryStatus.LOADING ? 'Analyzing...' : 'Visualize'}
          </button>
        </div>

        {/* Code Input (Kept Dark) */}
        <div className="flex-1 relative group">
          <textarea 
            ref={textareaRef}
            value={sqlInput}
            onChange={(e) => setSqlInput(e.target.value)}
            className="w-full h-full p-4 bg-gray-900 text-gray-300 font-mono text-sm resize-none focus:outline-none focus:ring-inset focus:ring-2 focus:ring-blue-500/50 selection:bg-blue-700 selection:text-white"
            spellCheck={false}
            placeholder="Paste your complex SQL query here..."
          />
        </div>

        {status === QueryStatus.ERROR && (
          <div className="p-4 bg-red-50 border-t border-red-200 text-red-700 text-sm">
            <strong>Error:</strong> {errorMsg}
          </div>
        )}
      </div>

      {/* Resizer Handle Left */}
      <div 
        className="w-1 cursor-col-resize hover:bg-blue-400 bg-gray-200 transition-colors z-20 flex-shrink-0"
        onMouseDown={() => setIsResizingSidebar(true)}
      />

      {/* Main Content Area (Light Mode) */}
      <div className="flex-1 flex flex-col relative bg-gray-50 overflow-hidden">
        {/* Graph Area */}
        <div className="flex-1 relative">
          {data ? (
            <QueryVisualizer 
              nodes={data.nodes} 
              onNodeSelect={setSelectedNode}
              selectedNodeId={selectedNode?.id}
            />
          ) : (
             <div className="absolute inset-0 flex flex-col items-center justify-center text-gray-400">
               {status === QueryStatus.LOADING ? (
                 <div className="flex flex-col items-center">
                   <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mb-4"></div>
                   <p className="text-gray-600 font-medium">Processing AST with Gemini AI...</p>
                 </div>
               ) : (
                 <>
                   <svg className="w-24 h-24 mb-4 opacity-10 text-gray-900" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19.428 15.428a2 2 0 00-1.022-.547l-2.384-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z"></path></svg>
                   <p className="text-gray-500">Enter a query and click Visualize to generate the Query Map.</p>
                 </>
               )}
             </div>
          )}
        </div>
      </div>

      {/* Resizer Handle Right */}
      <div 
        className="w-1 cursor-col-resize hover:bg-blue-400 bg-gray-200 transition-colors z-20 flex-shrink-0"
        onMouseDown={() => setIsResizingInspector(true)}
      />

      {/* Right Sidebar: Inspector (Resizable, Light Mode) */}
      <div 
        style={{ width: inspectorWidth }} 
        className="flex-shrink-0 border-l border-gray-200 bg-white z-10 shadow-xl"
      >
        <AstInspector node={selectedNode} />
      </div>
    </div>
  );
};

