        }
      }
    });

    if (!rootNode) return;

    // --- Configuration ---
    const nodeWidth = 240;
    const nodeHeight = 90;
    const horizontalSpacing = 60;
    const verticalSpacing = 100;

    // --- Tree Layout (Vertical) ---
    const hierarchy = d3.hierarchy<TreeData>(rootNode);

    const treeLayout = d3.tree<TreeData>()
      .nodeSize([nodeWidth + horizontalSpacing, nodeHeight + verticalSpacing])
      .separation((a, b) => a.parent === b.parent ? 1.1 : 1.3);

    const root = treeLayout(hierarchy);

    // --- Grid Background (Dot Pattern) ---
    // Defined BEFORE content group 'g' so it stays in the background
    const defs = svg.append("defs");
    const pattern = defs.append("pattern")
        .attr("id", "grid")
        .attr("width", 20)
        .attr("height", 20)
        .attr("patternUnits", "userSpaceOnUse");
    pattern.append("circle")
        .attr("cx", 2)
        .attr("cy", 2)
        .attr("r", 1)
        .attr("fill", "#e5e7eb");

    svg.append("rect")
       .attr("width", "100%")
       .attr("height", "100%")
       .attr("fill", "url(#grid)")
       .style("pointer-events", "none");

    // --- Zoom & Pan Setup ---
    const g = svg.append("g");

    const zoom = d3.zoom<SVGSVGElement, unknown>()
      .scaleExtent([0.1, 2])
      .on("zoom", (event) => {
        g.attr("transform", event.transform);
      });

    svg.call(zoom);

    // --- Draw Links ---
    g.selectAll(".link")
      .data(root.links())
      .enter().append("path")
      .attr("class", "link")
      .attr("fill", "none")
      .attr("stroke", "#9ca3af") // Gray-400
      .attr("stroke-width", 2)
      .attr("d", d3.linkVertical()
        .x(d => d.x)
        .y(d => d.y) as any
      );

    // --- Draw Nodes ---
    const nodeGroup = g.selectAll(".node")
      .data(root.descendants())
      .enter().append("g")
      .attr("class", "node")
      .attr("transform", d => `translate(${d.x},${d.y})`)
      .style("cursor", "pointer")
      .on("click", (event, d) => {
        onNodeSelect(d.data);
      });

    // 1. Node Card Background (Rect)
    nodeGroup.append("rect")
      .attr("width", nodeWidth)
      .attr("height", nodeHeight)
      .attr("x", -nodeWidth / 2)
      .attr("y", 0) 
      .attr("rx", 8)
      // Transition setup for smooth color change
      .style("transition", "fill 0.2s ease, stroke 0.2s ease, filter 0.2s ease") 
      .attr("fill", d => {
        const isSelected = d.data.id === selectedNodeId;
        const styles = getNodeStyles(d.data.type);
        return isSelected ? styles.solid : "#ffffff";
      })
      .attr("stroke", d => {
        const styles = getNodeStyles(d.data.type);
        return styles.solid;
      })
      .attr("stroke-width", 2)
      .style("filter", d => d.data.id === selectedNodeId 
        ? "drop-shadow(0px 8px 16px rgba(0,0,0,0.2))" 
        : "drop-shadow(0px 2px 4px rgba(0,0,0,0.1))"
      );

    // 2. Node Type Label (Badge)
    nodeGroup.append("rect")
      .attr("x", -nodeWidth / 2 + 10)
      .attr("y", 12)
      .attr("width", d => d.data.type.length * 7 + 10) 
      .attr("height", 18)
      .attr("rx", 4)
      .attr("fill", d => {
         const styles = getNodeStyles(d.data.type);
         // If node is selected (solid background), badge should be white to pop
         return d.data.id === selectedNodeId ? "#ffffff" : styles.soft;
      });

    nodeGroup.append("text")
      .attr("x", -nodeWidth / 2 + 15)
      .attr("y", 24)
      .text(d => d.data.type)
      .style("font-size", "10px")
      .style("font-weight", "bold")
      .style("fill", d => {
         const styles = getNodeStyles(d.data.type);
         // Text is always the solid color (on white badge or soft badge)
         return styles.text; 
      });

    // 3. Main Label
    nodeGroup.append("text")
      .attr("x", -nodeWidth / 2 + 12)
      .attr("y", 48) 
      .text(d => {
        const str = d.data.label;
        return str.length > 25 ? str.substring(0, 25) + "..." : str;
      })
      .style("font-size", "14px")
      .style("font-weight", "bold")
      .style("fill", d => d.data.id === selectedNodeId ? "#ffffff" : "#111827");

    // 4. Explanation Snippet
    nodeGroup.append("text")
      .attr("x", -nodeWidth / 2 + 12)
      .attr("y", 68)
      .text(d => {
         const str = d.data.explanation || "";
         return str.length > 35 ? str.substring(0, 35) + "..." : str;
      })
      .style("font-size", "11px")
      .style("fill", d => d.data.id === selectedNodeId ? "rgba(255,255,255,0.9)" : "#6b7280");

    // --- Initial Zoom to Fit/Center ---
    let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
    root.descendants().forEach(d => {
      minX = Math.min(minX, d.x - nodeWidth/2);
      maxX = Math.max(maxX, d.x + nodeWidth/2);
      minY = Math.min(minY, d.y);
      maxY = Math.max(maxY, d.y + nodeHeight);
    });

    const treeWidth = maxX - minX;
    const treeHeight = maxY - minY;

    const scale = Math.min(
      1.2, 
      Math.min(
        (dimensions.width - 100) / treeWidth,
        (dimensions.height - 100) / treeHeight
      )
    );

    const initialTransform = d3.zoomIdentity
      .translate(
        (dimensions.width - treeWidth * scale) / 2 - minX * scale, 
        (dimensions.height - treeHeight * scale) / 2 - minY * scale + 40
      )
      .scale(scale);

    svg.call(zoom.transform, initialTransform);

  }, [nodes, dimensions, selectedNodeId, onNodeSelect]);

  return (
    <div ref={wrapperRef} className="w-full h-full bg-gray-50 rounded-lg overflow-hidden relative border border-gray-200 shadow-inner">
      <div className="absolute top-4 left-4 text-xs text-gray-500 pointer-events-none z-10 flex flex-col gap-1 p-2 bg-white/80 rounded border border-gray-100 shadow-sm backdrop-blur-sm">
        <div className="flex items-center gap-2"><span className="w-3 h-3 rounded bg-purple-600"></span> CTE (Definition)</div>
        <div className="flex items-center gap-2"><span className="w-3 h-3 rounded bg-emerald-600"></span> Main Query</div>
        <div className="flex items-center gap-2"><span className="w-3 h-3 rounded bg-amber-600"></span> Subquery (Nested)</div>
      </div>
      <svg ref={svgRef} width="100%" height="100%"></svg>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { analyzeSql } from './services/geminiService';
import { AnalysisResult, QueryStatus, SqlNode } from './types';
import { QueryVisualizer } from './components/QueryVisualizer';
import { AstInspector } from './components/AstInspector';

// Example complex query for initial state
const DEFAULT_QUERY = `
WITH RegionalSales AS (
    SELECT region, SUM(amount) as total_sales
    FROM sales
    JOIN locations ON sales.location_id = locations.id
    WHERE sales.date > '2023-01-01'
    GROUP BY region
),
TopRegions AS (
    SELECT region
    FROM RegionalSales
    WHERE total_sales > 1000000
)
SELECT 
    e.employee_name,
    r.region,
    COUNT(o.id) as order_count
FROM employees e
JOIN orders o ON e.id = o.employee_id
JOIN TopRegions r ON e.region = r.region
WHERE o.status = 'completed'
GROUP BY e.employee_name, r.region
ORDER BY order_count DESC;
`;

const App: React.FC = () => {
  const [sqlInput, setSqlInput] = useState<string>(DEFAULT_QUERY.trim());
  const [status, setStatus] = useState<QueryStatus>(QueryStatus.IDLE);
  const [data, setData] = useState<AnalysisResult | null>(null);
  const [selectedNode, setSelectedNode] = useState<SqlNode | null>(null);
  const [errorMsg, setErrorMsg] = useState<string>("");

  // Refs for synced scrolling
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const backdropRef = useRef<HTMLDivElement>(null);

  // Layout State
  const [sidebarWidth, setSidebarWidth] = useState(400);
  const [inspectorWidth, setInspectorWidth] = useState(380);
  const [isResizingSidebar, setIsResizingSidebar] = useState(false);
  const [isResizingInspector, setIsResizingInspector] = useState(false);

  // Resize Handlers
  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (isResizingSidebar) {
        setSidebarWidth(Math.max(250, Math.min(600, e.clientX)));
      }
      if (isResizingInspector) {
        // Inspector is now the middle panel.
        // e.clientX represents the right edge of the Inspector panel.
        // We calculate width by subtracting the sidebar width (left edge of Inspector).
        const newWidth = e.clientX - sidebarWidth;
        setInspectorWidth(Math.max(300, Math.min(800, newWidth)));
      }
    };

    const handleMouseUp = () => {
      setIsResizingSidebar(false);
      setIsResizingInspector(false);
      document.body.style.cursor = 'default';
    };

    if (isResizingSidebar || isResizingInspector) {
      document.addEventListener('mousemove', handleMouseMove);
      document.addEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = 'col-resize';
    }

    return () => {
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = 'default';
    };
  }, [isResizingSidebar, isResizingInspector, sidebarWidth]);

  // Sync scroll between textarea and backdrop
  const handleScroll = () => {
    if (textareaRef.current && backdropRef.current) {
      backdropRef.current.scrollTop = textareaRef.current.scrollTop;
      backdropRef.current.scrollLeft = textareaRef.current.scrollLeft;
    }
  };

  // Scroll to highlight when selection changes
  useEffect(() => {
    if (selectedNode && textareaRef.current) {
      const snippet = selectedNode.sqlSnippet;
      if (!snippet) return;

      let startIdx = sqlInput.indexOf(snippet);
      if (startIdx === -1) {
        startIdx = sqlInput.indexOf(snippet.trim());
      }

      if (startIdx !== -1) {
        // We still focus the textarea so keyboard works immediately
        textareaRef.current.focus();
        // Determine line number to scroll to roughly
        const textBefore = sqlInput.substring(0, startIdx);
        const linesBefore = textBefore.split('\n').length;
        const lineHeight = 20; // Approx line height in px for text-sm

        // Smooth scroll the textarea (which syncs the backdrop via onScroll)
        textareaRef.current.scrollTo({
          top: (linesBefore - 2) * lineHeight, 
          behavior: 'smooth'
        });
      }
    }
  }, [selectedNode]);

  const handleAnalyze = async () => {
    if (!sqlInput.trim()) return;

    setStatus(QueryStatus.LOADING);
    setErrorMsg("");
    setSelectedNode(null);

    try {
      const result = await analyzeSql(sqlInput);
      setData(result);

      // Default to MAIN_QUERY if available, otherwise ROOT
      const defaultNode = result.nodes.find(n => n.type === 'MAIN_QUERY') || result.nodes.find(n => n.type === 'ROOT');
      if (defaultNode) setSelectedNode(defaultNode);

      setStatus(QueryStatus.SUCCESS);
    } catch (err: any) {
      console.error(err);
      setErrorMsg(err.message || "Failed to analyze SQL. Please check your API key or input.");
      setStatus(QueryStatus.ERROR);
    }
  };

  // Render the highlighted text for the backdrop
  const renderHighlightedText = () => {
    if (!selectedNode || !selectedNode.sqlSnippet) {
      return <span className="text-gray-800">{sqlInput}</span>;
    }

    const snippet = selectedNode.sqlSnippet;
    let startIdx = sqlInput.indexOf(snippet);
    let matchLength = snippet.length;

    if (startIdx === -1) {
      const trimmed = snippet.trim();
      startIdx = sqlInput.indexOf(trimmed);
      matchLength = trimmed.length;
    }

    if (startIdx === -1) return <span className="text-gray-800">{sqlInput}</span>;

    const before = sqlInput.substring(0, startIdx);
    const match = sqlInput.substring(startIdx, startIdx + matchLength);
    const after = sqlInput.substring(startIdx + matchLength);

    return (
      <>
        <span className="text-gray-400 opacity-50 transition-opacity duration-300">{before}</span>
        <span className="bg-blue-100 text-blue-900 rounded border-b-2 border-blue-500 font-bold shadow-sm px-0.5 box-decoration-clone">
          {match}
        </span>
        <span className="text-gray-400 opacity-50 transition-opacity duration-300">{after}</span>
      </>
    );
  };

  return (
    <div className="flex h-screen w-full bg-white text-gray-900 font-sans overflow-hidden">

      {/* 1. Sidebar: Input (Resizable) */}
      <div 
        style={{ width: sidebarWidth }} 
        className="flex-shrink-0 flex flex-col border-r border-gray-200 bg-gray-50 transition-colors"
      >
        <div className="p-4 border-b border-gray-200 flex justify-between items-center bg-white">
          <div className="flex items-center gap-2">
            <div className="w-3 h-3 rounded-full bg-blue-600"></div>
            <h1 className="text-lg font-bold text-gray-800 tracking-tight">SQL Vision</h1>
          </div>
          <button 
            onClick={handleAnalyze}
            disabled={status === QueryStatus.LOADING}
            className={`px-4 py-1.5 rounded text-sm font-semibold transition-all shadow-sm ${
              status === QueryStatus.LOADING 
              ? 'bg-gray-100 text-gray-400 cursor-wait' 
              : 'bg-blue-600 hover:bg-blue-700 text-white shadow-blue-500/20'
            }`}
          >
            {status === QueryStatus.LOADING ? 'Analyzing...' : 'Visualize'}
          </button>
        </div>

        {/* Custom Layered Editor (Light Mode) */}
        <div className="flex-1 relative group overflow-hidden bg-white">

          {/* Layer 1: Backdrop (Presentation) */}
          <div 
            ref={backdropRef}
            className="absolute inset-0 p-4 font-mono text-sm whitespace-pre-wrap break-words overflow-auto pointer-events-none z-0 custom-scrollbar"
            style={{ fontFamily: 'Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace', lineHeight: '1.6' }}
          >
            {renderHighlightedText()}
            {/* Add extra space at bottom to match textarea behavior */}
            <div className="h-8"></div> 
          </div>

          {/* Layer 2: Textarea (Interaction) */}
          <textarea 
            ref={textareaRef}
            value={sqlInput}
            onChange={(e) => setSqlInput(e.target.value)}
            onScroll={handleScroll}
            className="absolute inset-0 w-full h-full p-4 font-mono text-sm whitespace-pre-wrap break-words bg-transparent text-transparent caret-blue-600 resize-none focus:outline-none z-10 custom-scrollbar selection:bg-blue-100 selection:text-blue-900"
            style={{ fontFamily: 'Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace', lineHeight: '1.6' }}
            spellCheck={false}
            placeholder="Paste your complex SQL query here..."
          />
        </div>

        {status === QueryStatus.ERROR && (
          <div className="p-4 bg-red-50 border-t border-red-200 text-red-700 text-sm">
            <strong>Error:</strong> {errorMsg}
          </div>
        )}
      </div>

      {/* Resizer Handle 1 (Left) */}
      <div 
        className="w-1 cursor-col-resize hover:bg-blue-400 bg-gray-200 transition-colors z-20 flex-shrink-0"
        onMouseDown={() => setIsResizingSidebar(true)}
      />

      {/* 2. Middle: Inspector (Resizable) - MOVED HERE */}
      <div 
        style={{ width: inspectorWidth }} 
        className="flex-shrink-0 border-r border-gray-200 bg-white z-10 flex flex-col"
      >
        <AstInspector node={selectedNode} />
      </div>

      {/* Resizer Handle 2 (Right) - MOVED HERE */}
      <div 
        className="w-1 cursor-col-resize hover:bg-blue-400 bg-gray-200 transition-colors z-20 flex-shrink-0"
        onMouseDown={() => setIsResizingInspector(true)}
      />

      {/* 3. Main Content: Graph Area (Light Mode) - MOVED HERE */}
      <div className="flex-1 flex flex-col relative bg-gray-50 overflow-hidden">
        {/* Graph Area */}
        <div className="flex-1 relative">
          {data ? (
            <QueryVisualizer 
              nodes={data.nodes} 
              onNodeSelect={setSelectedNode}
              selectedNodeId={selectedNode?.id}
            />
          ) : (
             <div className="absolute inset-0 flex flex-col items-center justify-center text-gray-400">
               {status === QueryStatus.LOADING ? (
                 <div className="flex flex-col items-center">
                   <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mb-4"></div>
                   <p className="text-gray-600 font-medium">Processing AST with Gemini AI...</p>
                 </div>
               ) : (
                 <>
                   <svg className="w-24 h-24 mb-4 opacity-10 text-gray-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19.428 15.428a2 2 0 00-1.022-.547l-2.384-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z"></path></svg>
                   <p className="text-gray-400">Enter a query and click Visualize to generate the Query Map.</p>
                 </>
               )}
             </div>
          )}
        </div>
      </div>

    </div>
  );
};

export default App;

export interface AstSource {
  table: string;
  alias?: string;
}

export interface AstColumn {
  name: string;       // The output name (alias or column name)
  expression: string; // The underlying logic/calculation
}

export interface AstJoin {
  type: string; // INNER, LEFT, etc.
  table: string; // The table being joined
  condition: string; // The ON clause
}

export interface AstDetails {
  columns: AstColumn[];
  sources: AstSource[]; 
  joins: AstJoin[];
  conditions: string[]; // Where/Having clauses
  groupBy?: string[];
  orderBy?: string[];
}

export interface SqlNode {
  id: string;
  label: string; // Short name e.g. "Main Query", "Subquery A"
  type: 'ROOT' | 'CTE_BLOCK' | 'CTE' | 'MAIN_QUERY' | 'SUBQUERY' | 'UNION' | 'JOIN_PART';
  sqlSnippet: string;
  explanation: string;
  parentId?: string | null; // For tree construction
  ast: AstDetails;
}

export interface AnalysisResult {
  nodes: SqlNode[];
}

export enum QueryStatus {
  IDLE = 'IDLE',
  LOADING = 'LOADING',
  SUCCESS = 'SUCCESS',
  ERROR = 'ERROR'
}

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const SYSTEM_INSTRUCTION = `
You are an expert SQL parser and visualizer backend. 
Your task is to analyze the SYNTACTIC structure of a SQL query and return a hierarchical tree of nodes.

**CRITICAL RULES FOR HIERARCHY:**
1. **Root Node**: Represents the entire SQL file/input.
2. **CTE Definitions**: If the query uses a WITH clause, each CTE (Common Table Expression) definition must be a DIRECT CHILD of the Root Node.
   - **IMPORTANT**: Even if "CTE_B" selects from "CTE_A", treat them as SIBLING definitions in the WITH block. Do NOT nest CTEs inside each other. They are parallel definitions.
3. **Main Query**: The primary SELECT/INSERT/UPDATE statement is a sibling of the CTEs (child of Root).
4. **Subqueries**: Any SELECT statement nested physically inside a FROM, JOIN, WHERE, HAVING, or Projection clause must be a CHILD of the node containing it.
   - Example: "SELECT * FROM (SELECT ...)" -> The inner SELECT is a child of the outer SELECT.
5. **Unions**: If parts are combined via UNION, they are children of the UNION parent.

**Output Schema Requirements:**
For each node, provide:
- **id**: Unique string.
- **label**: Short name.
- **type**: One of ['ROOT', 'CTE', 'MAIN_QUERY', 'SUBQUERY', 'UNION'].
- **parentId**: The ID of the syntactic container node.
- **sqlSnippet**: The EXACT character-for-character substring.
- **ast**: Extract key details:
  - **columns**: Array of objects { name: "output_name", expression: "formula_or_source" }.
  - **sources**: Array of objects { table: "table_name", alias: "alias_if_exists" }.
  - **joins**: Array of objects { type: "INNER/LEFT", table: "target_table", condition: "on_clause" }.
  - **conditions**: Simple string array of WHERE/HAVING clauses.
`;

export const analyzeSql = async (sql: string): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Analyze this SQL query structure:\n\n${sql}`,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            nodes: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING, description: "Unique ID like 'node_1'" },
                  label: { type: Type.STRING, description: "Human readable label" },
                  type: { type: Type.STRING, enum: ['ROOT', 'CTE', 'MAIN_QUERY', 'SUBQUERY', 'UNION', 'JOIN_PART'] },
                  sqlSnippet: { type: Type.STRING, description: "The EXACT source code substring for this block" },
                  explanation: { type: Type.STRING, description: "Brief explanation of what this block does" },
                  parentId: { type: Type.STRING, description: "ID of the parent node. Null if Root.", nullable: true },
                  ast: {
                    type: Type.OBJECT,
                    properties: {
                      columns: { 
                        type: Type.ARRAY, 
                        items: { 
                          type: Type.OBJECT,
                          properties: {
                            name: { type: Type.STRING, description: "The alias or output column name" },
                            expression: { type: Type.STRING, description: "The original expression or column, e.g. SUM(amount)" }
                          },
                          required: ["name", "expression"]
                        } 
                      },
                      sources: { 
                        type: Type.ARRAY, 
                        items: { 
                          type: Type.OBJECT,
                          properties: {
                            table: { type: Type.STRING },
                            alias: { type: Type.STRING, nullable: true }
                          },
                          required: ["table"]
                        } 
                      },
                      joins: { 
                        type: Type.ARRAY, 
                        items: { 
                          type: Type.OBJECT,
                          properties: {
                            type: { type: Type.STRING },
                            table: { type: Type.STRING },
                            condition: { type: Type.STRING }
                          },
                          required: ["type", "table", "condition"]
                        } 
                      },
                      conditions: { type: Type.ARRAY, items: { type: Type.STRING } },
                      groupBy: { type: Type.ARRAY, items: { type: Type.STRING } },
                      orderBy: { type: Type.ARRAY, items: { type: Type.STRING } },
                    },
                    required: ["columns", "sources", "joins", "conditions"]
                  }
                },
                required: ["id", "label", "type", "sqlSnippet", "explanation", "ast"]
              }
            }
          },
          required: ["nodes"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as AnalysisResult;

  } catch (error) {
    console.error("Gemini Analysis Failed:", error);
    throw error;
  }
};

import React from 'react';
import { SqlNode, AstColumn, AstSource, AstJoin } from '../types';

interface AstInspectorProps {
  node: SqlNode | null;
}

const DetailSection: React.FC<{ title: string; children: React.ReactNode }> = ({ title, children }) => {
  if (!children) return null;
  // If children is an array and empty, don't render
  if (Array.isArray(children) && children.length === 0) return null;

  return (
    <div className="mb-6">
      <h4 className="text-xs uppercase tracking-wider text-gray-400 font-bold mb-3 flex items-center gap-2">
        {title}
      </h4>
      <div className="flex flex-col gap-2">
        {children}
      </div>
    </div>
  );
};

export const AstInspector: React.FC<AstInspectorProps> = ({ node }) => {
  if (!node) {
    return (
      <div className="h-full flex items-center justify-center text-gray-500 p-8 text-center bg-white">
        <p>Select a node in the graph to view its Abstract Syntax Tree (AST).</p>
      </div>
    );
  }

  const getTypeStyle = (type: string) => {
    switch (type) {
      case 'ROOT': return 'bg-red-100 text-red-800 border-red-200';
      case 'CTE': return 'bg-purple-100 text-purple-800 border-purple-200';
      case 'MAIN_QUERY': return 'bg-emerald-100 text-emerald-800 border-emerald-200';
      case 'SUBQUERY': return 'bg-amber-100 text-amber-800 border-amber-200';
      default: return 'bg-gray-100 text-gray-800 border-gray-200';
    }
  };

  return (
    <div className="h-full flex flex-col bg-white overflow-hidden">
      {/* Header */}
      <div className="p-4 border-b border-gray-200 bg-gray-50/50">
        <div className="flex items-center justify-between mb-2">
          <span className={`px-2 py-0.5 rounded text-xs font-bold border ${getTypeStyle(node.type)}`}>
            {node.type}
          </span>
          <span className="text-gray-400 text-xs font-mono">{node.id}</span>
        </div>
        <h2 className="text-lg font-bold text-gray-900 mb-2 leading-tight">{node.label}</h2>
        <p className="text-sm text-gray-600">{node.explanation}</p>
      </div>

      {/* Content */}
      <div className="flex-1 overflow-y-auto p-4 custom-scrollbar">

        <div className="space-y-6">

          {/* Columns */}
          {node.ast.columns.length > 0 && (
            <DetailSection title="Projections (Columns)">
              <div className="grid grid-cols-1 gap-2">
                {node.ast.columns.map((col, idx) => (
                  <div key={idx} className="p-2 bg-gray-50 border border-gray-100 rounded text-sm flex flex-col">
                    <span className="font-bold text-gray-800">{col.name}</span>
                    {col.expression && col.expression !== col.name && (
                      <div className="flex items-center gap-1 mt-1 text-xs text-gray-500 font-mono bg-gray-100/50 p-1 rounded w-fit">
                        <span className="text-gray-400">fn:</span>
                        {col.expression}
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </DetailSection>
          )}

          {/* Sources */}
          {node.ast.sources.length > 0 && (
            <DetailSection title="Sources (From)">
              {node.ast.sources.map((src, idx) => (
                <div key={idx} className="flex items-center justify-between p-2 bg-blue-50 border border-blue-100 rounded text-sm">
                  <span className="font-semibold text-blue-900">{src.table}</span>
                  {src.alias && (
                    <span className="px-1.5 py-0.5 bg-blue-100 text-blue-600 rounded text-xs font-mono">
                      AS {src.alias}
                    </span>
                  )}
                </div>
              ))}
            </DetailSection>
          )}

          {/* Joins */}
          {node.ast.joins.length > 0 && (
            <DetailSection title="Joins">
              {node.ast.joins.map((join, idx) => (
                <div key={idx} className="relative pl-3 border-l-2 border-gray-300 py-1">
                   <div className="flex items-center gap-2 mb-1">
                      <span className="text-xs font-bold uppercase text-gray-500 bg-gray-100 px-1 rounded">{join.type} JOIN</span>
                      <span className="font-bold text-gray-800 text-sm">{join.table}</span>
                   </div>
                   <div className="text-xs font-mono text-gray-600 bg-gray-50 p-1.5 rounded border border-gray-100">
                      ON {join.condition}
                   </div>
                </div>
              ))}
            </DetailSection>
          )}

          {/* Conditions */}
          {node.ast.conditions.length > 0 && (
             <DetailSection title="Conditions">
               {node.ast.conditions.map((cond, idx) => (
                 <div key={idx} className="px-2 py-1.5 bg-yellow-50 border border-yellow-100 rounded text-sm text-yellow-900 font-mono break-words">
                   {cond}
                 </div>
               ))}
             </DetailSection>
          )}

          {/* Group By / Order By */}
          {(node.ast.groupBy?.length ?? 0) > 0 && (
             <DetailSection title="Group By">
                <div className="flex flex-wrap gap-2">
                   {node.ast.groupBy?.map((g, i) => (
                      <span key={i} className="px-2 py-1 bg-gray-100 rounded text-xs font-mono text-gray-700">{g}</span>
                   ))}
                </div>
             </DetailSection>
          )}

           {(node.ast.orderBy?.length ?? 0) > 0 && (
             <DetailSection title="Order By">
                <div className="flex flex-wrap gap-2">
                   {node.ast.orderBy?.map((o, i) => (
                      <span key={i} className="px-2 py-1 bg-gray-100 rounded text-xs font-mono text-gray-700">{o}</span>
                   ))}
                </div>
             </DetailSection>
          )}

        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useRef, useState } from 'react';
import * as d3 from 'd3';
import { SqlNode } from '../types';

interface QueryVisualizerProps {
  nodes: SqlNode[];
  onNodeSelect: (node: SqlNode) => void;
  selectedNodeId?: string;
}

interface TreeData extends SqlNode {
  children?: TreeData[];
}

// Helper for consistent colors
const getNodeStyles = (type: string) => {
  switch (type) {
    case 'ROOT': return { solid: "#dc2626", soft: "#fef2f2", text: "#b91c1c" }; // Red-600, Red-50
    case 'CTE': return { solid: "#9333ea", soft: "#faf5ff", text: "#7e22ce" }; // Purple-600, Purple-50
    case 'MAIN_QUERY': return { solid: "#059669", soft: "#ecfdf5", text: "#047857" }; // Emerald-600, Emerald-50
    case 'SUBQUERY': return { solid: "#d97706", soft: "#fffbeb", text: "#b45309" }; // Amber-600, Amber-50
    default: return { solid: "#4b5563", soft: "#f3f4f6", text: "#374151" }; // Gray-600, Gray-50
  }
};

export const QueryVisualizer: React.FC<QueryVisualizerProps> = ({ nodes, onNodeSelect, selectedNodeId }) => {
  const svgRef = useRef<SVGSVGElement>(null);
  const wrapperRef = useRef<HTMLDivElement>(null);
  const zoomRef = useRef<d3.ZoomBehavior<SVGSVGElement, unknown> | null>(null);
  const [dimensions, setDimensions] = useState({ width: 800, height: 600 });
  const [hasRendered, setHasRendered] = useState(false);

  useEffect(() => {
    const handleResize = () => {
      if (wrapperRef.current) {
        const { width, height } = wrapperRef.current.getBoundingClientRect();
        setDimensions({ width, height });
      }
    };
    window.addEventListener('resize', handleResize);
    handleResize(); 
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // --- Zoom Controls ---
  const handleZoomIn = () => {
    if (svgRef.current && zoomRef.current) {
      d3.select(svgRef.current)
        .transition()
        .duration(300)
        .call(zoomRef.current.scaleBy, 1.2);
    }
  };

  const handleZoomOut = () => {
    if (svgRef.current && zoomRef.current) {
      d3.select(svgRef.current)
        .transition()
        .duration(300)
        .call(zoomRef.current.scaleBy, 0.8);
    }
  };

  const handleReset = () => {
    // We re-trigger the initial zoom calculation logic by forcing a re-render or calling logic directly
    // Ideally we just want to run the "Zoom to Fit" logic again.
    // The easiest way with the current cleanup structure is to let the Effect dependency trigger, 
    // but that requires state change. Instead, I'll extract the fit logic or just set hasRendered to false briefly.
    setHasRendered(false);
  };

  useEffect(() => {
    if (!nodes.length || !svgRef.current) return;

    const svg = d3.select(svgRef.current);
    svg.selectAll("*").remove(); // Clear previous

    // --- Data Preparation ---
    const dataMap = new Map<string, TreeData>();
    nodes.forEach(node => dataMap.set(node.id, { ...node, children: [] }));

    let rootNode: TreeData | null = null;
    nodes.forEach(node => {
      if (node.parentId && dataMap.has(node.parentId)) {
        dataMap.get(node.parentId)!.children!.push(dataMap.get(node.id)!);
      } else {
        if (!rootNode || node.type === 'ROOT') {
          rootNode = dataMap.get(node.id)!;
        }
      }
    });

    if (!rootNode) return;

    // --- Configuration ---
    const nodeWidth = 240;
    const nodeHeight = 90;
    const horizontalSpacing = 60;
    const verticalSpacing = 100;

    // --- Tree Layout (Vertical) ---
    const hierarchy = d3.hierarchy<TreeData>(rootNode);

    const treeLayout = d3.tree<TreeData>()
      .nodeSize([nodeWidth + horizontalSpacing, nodeHeight + verticalSpacing])
      .separation((a, b) => a.parent === b.parent ? 1.1 : 1.3);

    const root = treeLayout(hierarchy);

    // --- Grid Background (Dot Pattern) ---
    const defs = svg.append("defs");
    const pattern = defs.append("pattern")
        .attr("id", "grid")
        .attr("width", 20)
        .attr("height", 20)
        .attr("patternUnits", "userSpaceOnUse");
    pattern.append("circle")
        .attr("cx", 2)
        .attr("cy", 2)
        .attr("r", 1)
        .attr("fill", "#e5e7eb");

    svg.append("rect")
       .attr("width", "100%")
       .attr("height", "100%")
       .attr("fill", "url(#grid)")
       .style("pointer-events", "none");

    // --- Zoom & Pan Setup ---
    const g = svg.append("g");

    const zoom = d3.zoom<SVGSVGElement, unknown>()
      .scaleExtent([0.1, 3])
      .on("zoom", (event) => {
        g.attr("transform", event.transform);
      });

    zoomRef.current = zoom;
    svg.call(zoom);

    // --- Draw Links ---
    g.selectAll(".link")
      .data(root.links())
      .enter().append("path")
      .attr("class", "link")
      .attr("fill", "none")
      .attr("stroke", "#9ca3af") // Gray-400
      .attr("stroke-width", 2)
      .attr("d", d3.linkVertical()
        .x(d => d.x)
        .y(d => d.y) as any
      );

    // --- Draw Nodes ---
    const nodeGroup = g.selectAll(".node")
      .data(root.descendants())
      .enter().append("g")
      .attr("class", "node")
      .attr("transform", d => `translate(${d.x},${d.y})`)
      .style("cursor", "pointer")
      .on("click", (event, d) => {
        onNodeSelect(d.data);
      });

    // 1. Node Card Background (Rect)
    nodeGroup.append("rect")
      .attr("width", nodeWidth)
      .attr("height", nodeHeight)
      .attr("x", -nodeWidth / 2)
      .attr("y", 0) 
      .attr("rx", 8)
      .style("transition", "fill 0.2s ease, stroke 0.2s ease, filter 0.2s ease") 
      .attr("fill", d => {
        const isSelected = d.data.id === selectedNodeId;
        const styles = getNodeStyles(d.data.type);
        return isSelected ? styles.solid : "#ffffff";
      })
      .attr("stroke", d => {
        const styles = getNodeStyles(d.data.type);
        return styles.solid;
      })
      .attr("stroke-width", 2)
      .style("filter", d => d.data.id === selectedNodeId 
        ? "drop-shadow(0px 8px 16px rgba(0,0,0,0.2))" 
        : "drop-shadow(0px 2px 4px rgba(0,0,0,0.1))"
      );

    // 2. Node Type Label (Badge)
    nodeGroup.append("rect")
      .attr("x", -nodeWidth / 2 + 10)
      .attr("y", 12)
      .attr("width", d => d.data.type.length * 7 + 10) 
      .attr("height", 18)
      .attr("rx", 4)
      .attr("fill", d => {
         const styles = getNodeStyles(d.data.type);
         return d.data.id === selectedNodeId ? "#ffffff" : styles.soft;
      });

    nodeGroup.append("text")
      .attr("x", -nodeWidth / 2 + 15)
      .attr("y", 24)
      .text(d => d.data.type)
      .style("font-size", "10px")
      .style("font-weight", "bold")
      .style("fill", d => {
         const styles = getNodeStyles(d.data.type);
         return styles.text; 
      });

    // 3. Main Label
    nodeGroup.append("text")
      .attr("x", -nodeWidth / 2 + 12)
      .attr("y", 48) 
      .text(d => {
        const str = d.data.label;
        return str.length > 25 ? str.substring(0, 25) + "..." : str;
      })
      .style("font-size", "14px")
      .style("font-weight", "bold")
      .style("fill", d => d.data.id === selectedNodeId ? "#ffffff" : "#111827");

    // 4. Explanation Snippet
    nodeGroup.append("text")
      .attr("x", -nodeWidth / 2 + 12)
      .attr("y", 68)
      .text(d => {
         const str = d.data.explanation || "";
         return str.length > 35 ? str.substring(0, 35) + "..." : str;
      })
      .style("font-size", "11px")
      .style("fill", d => d.data.id === selectedNodeId ? "rgba(255,255,255,0.9)" : "#6b7280");

    // --- Initial Zoom to Fit/Center ---
    // Only run this if we are rendering for the first time or explicitly reset (via hasRendered toggling)
    if (!hasRendered || dimensions.width > 0) { 
       let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
       root.descendants().forEach(d => {
         minX = Math.min(minX, d.x - nodeWidth/2);
         maxX = Math.max(maxX, d.x + nodeWidth/2);
         minY = Math.min(minY, d.y);
         maxY = Math.max(maxY, d.y + nodeHeight);
       });

       const treeWidth = maxX - minX;
       const treeHeight = maxY - minY;

       // Add some padding
       const paddingX = 100;
       const paddingY = 100;

       const availableWidth = dimensions.width - paddingX;
       const availableHeight = dimensions.height - paddingY;

       let scale = Math.min(
         1.2, 
         Math.min(availableWidth / treeWidth, availableHeight / treeHeight)
       );

       if (!isFinite(scale)) scale = 0.5;

       const initialTransform = d3.zoomIdentity
         .translate(
           (dimensions.width - treeWidth * scale) / 2 - minX * scale, 
           (dimensions.height - treeHeight * scale) / 2 - minY * scale + 40
         )
         .scale(scale);

       svg.call(zoom.transform, initialTransform);
       setHasRendered(true);
    }

  }, [nodes, dimensions, selectedNodeId, onNodeSelect, hasRendered]);

  return (
    <div ref={wrapperRef} className="w-full h-full bg-gray-50 rounded-lg overflow-hidden relative border border-gray-200 shadow-inner group">

      {/* Legend */}
      <div className="absolute top-4 left-4 text-xs text-gray-500 pointer-events-none z-10 flex flex-col gap-1 p-2 bg-white/80 rounded border border-gray-100 shadow-sm backdrop-blur-sm">
        <div className="flex items-center gap-2"><span className="w-3 h-3 rounded bg-purple-600"></span> CTE (Definition)</div>
        <div className="flex items-center gap-2"><span className="w-3 h-3 rounded bg-emerald-600"></span> Main Query</div>
        <div className="flex items-center gap-2"><span className="w-3 h-3 rounded bg-amber-600"></span> Subquery (Nested)</div>
      </div>

      {/* Zoom Controls */}
      <div className="absolute bottom-4 right-4 flex flex-col gap-2 z-10">
        <button 
          onClick={handleZoomIn}
          className="w-8 h-8 flex items-center justify-center bg-white border border-gray-200 rounded shadow hover:bg-gray-50 text-gray-700 font-bold text-lg"
          title="Zoom In"
        >
          +
        </button>
        <button 
          onClick={handleReset}
          className="w-8 h-8 flex items-center justify-center bg-white border border-gray-200 rounded shadow hover:bg-gray-50 text-gray-700"
          title="Fit to Screen"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 0l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5l-5-5m5 5v-4m0 4h-4"></path></svg>
        </button>
        <button 
          onClick={handleZoomOut}
          className="w-8 h-8 flex items-center justify-center bg-white border border-gray-200 rounded shadow hover:bg-gray-50 text-gray-700 font-bold text-lg"
          title="Zoom Out"
        >
          -
        </button>
      </div>

      <svg ref={svgRef} width="100%" height="100%"></svg>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const SYSTEM_INSTRUCTION = `
You are an expert SQL parser and visualizer backend. 
Your task is to analyze the SYNTACTIC structure of a SQL query and return a hierarchical tree of nodes.

**LANGUAGE REQUIREMENT:**
- The **structure** (keys like id, type, ast) must remain in English.
- The **content** for 'label' and 'explanation' MUST be in **Simplified Chinese (简体中文)**.

**CRITICAL RULES FOR HIERARCHY:**
1. **Root Node**: Represents the entire SQL file/input.
2. **CTE Definitions**: If the query uses a WITH clause, each CTE (Common Table Expression) definition must be a DIRECT CHILD of the Root Node.
   - **IMPORTANT**: Even if "CTE_B" selects from "CTE_A", treat them as SIBLING definitions in the WITH block. Do NOT nest CTEs inside each other. They are parallel definitions.
3. **Main Query**: The primary SELECT/INSERT/UPDATE statement is a sibling of the CTEs (child of Root).
4. **Subqueries**: Any SELECT statement nested physically inside a FROM, JOIN, WHERE, HAVING, or Projection clause must be a CHILD of the node containing it.
   - Example: "SELECT * FROM (SELECT ...)" -> The inner SELECT is a child of the outer SELECT.
5. **Unions**: If parts are combined via UNION, they are children of the UNION parent.

**Output Schema Requirements:**
For each node, provide:
- **id**: Unique string.
- **label**: Short name in Chinese (e.g., "主查询", "区域销售CTE").
- **type**: One of ['ROOT', 'CTE', 'MAIN_QUERY', 'SUBQUERY', 'UNION', 'JOIN_PART'].
- **parentId**: The ID of the syntactic container node.
- **sqlSnippet**: The EXACT character-for-character substring.
- **ast**: Extract key details:
  - **columns**: Array of objects { name: "output_name", expression: "formula_or_source" }.
  - **sources**: Array of objects { table: "table_name", alias: "alias_if_exists" }.
  - **joins**: Array of objects { type: "INNER/LEFT", table: "target_table", condition: "on_clause" }.
  - **conditions**: Simple string array of WHERE/HAVING clauses.
`;

export const analyzeSql = async (sql: string): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Analyze this SQL query structure:\n\n${sql}`,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            nodes: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING, description: "Unique ID like 'node_1'" },
                  label: { type: Type.STRING, description: "Human readable label in Chinese" },
                  type: { type: Type.STRING, enum: ['ROOT', 'CTE', 'MAIN_QUERY', 'SUBQUERY', 'UNION', 'JOIN_PART'] },
                  sqlSnippet: { type: Type.STRING, description: "The EXACT source code substring for this block" },
                  explanation: { type: Type.STRING, description: "Brief explanation of what this block does in Chinese" },
                  parentId: { type: Type.STRING, description: "ID of the parent node. Null if Root.", nullable: true },
                  ast: {
                    type: Type.OBJECT,
                    properties: {
                      columns: { 
                        type: Type.ARRAY, 
                        items: { 
                          type: Type.OBJECT,
                          properties: {
                            name: { type: Type.STRING, description: "The alias or output column name" },
                            expression: { type: Type.STRING, description: "The original expression or column, e.g. SUM(amount)" }
                          },
                          required: ["name", "expression"]
                        } 
                      },
                      sources: { 
                        type: Type.ARRAY, 
                        items: { 
                          type: Type.OBJECT,
                          properties: {
                            table: { type: Type.STRING },
                            alias: { type: Type.STRING, nullable: true }
                          },
                          required: ["table"]
                        } 
                      },
                      joins: { 
                        type: Type.ARRAY, 
                        items: { 
                          type: Type.OBJECT,
                          properties: {
                            type: { type: Type.STRING },
                            table: { type: Type.STRING },
                            condition: { type: Type.STRING }
                          },
                          required: ["type", "table", "condition"]
                        } 
                      },
                      conditions: { type: Type.ARRAY, items: { type: Type.STRING } },
                      groupBy: { type: Type.ARRAY, items: { type: Type.STRING } },
                      orderBy: { type: Type.ARRAY, items: { type: Type.STRING } },
                    },
                    required: ["columns", "sources", "joins", "conditions"]
                  }
                },
                required: ["id", "label", "type", "sqlSnippet", "explanation", "ast"]
              }
            }
          },
          required: ["nodes"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as AnalysisResult;

  } catch (error) {
    console.error("Gemini Analysis Failed:", error);
    throw error;
  }
};

import React, { useState } from 'react';
import { SqlNode, AstColumn, AstSource, AstJoin } from '../types';

interface AstInspectorProps {
  node: SqlNode | null;
}

const DetailSection: React.FC<{ title: string; children: React.ReactNode; defaultOpen?: boolean }> = ({ title, children, defaultOpen = true }) => {
  const [isOpen, setIsOpen] = useState(defaultOpen);

  if (!children) return null;
  // If children is an array and empty, don't render
  if (Array.isArray(children) && children.length === 0) return null;

  return (
    <div className="border border-gray-200 rounded-lg overflow-hidden bg-white shadow-sm mb-3">
      <button 
        onClick={() => setIsOpen(!isOpen)}
        className="w-full flex items-center justify-between p-3 bg-gray-50 hover:bg-gray-100 transition-colors text-left"
      >
        <span className="text-xs uppercase tracking-wider text-gray-600 font-bold flex items-center gap-2">
          {title}
        </span>
        <svg 
          className={`w-4 h-4 text-gray-400 transition-transform duration-200 ${isOpen ? 'transform rotate-180' : ''}`} 
          fill="none" 
          stroke="currentColor" 
          viewBox="0 0 24 24"
        >
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" />
        </svg>
      </button>

      {isOpen && (
        <div className="p-3 bg-white border-t border-gray-100 flex flex-col gap-2 animate-in slide-in-from-top-1 duration-200">
          {children}
        </div>
      )}
    </div>
  );
};

export const AstInspector: React.FC<AstInspectorProps> = ({ node }) => {
  if (!node) {
    return (
      <div className="h-full flex items-center justify-center text-gray-500 p-8 text-center bg-white">
        <p>在图表中选择一个节点以查看其抽象语法树 (AST)。</p>
      </div>
    );
  }

  const getTypeStyle = (type: string) => {
    switch (type) {
      case 'ROOT': return 'bg-red-100 text-red-800 border-red-200';
      case 'CTE': return 'bg-purple-100 text-purple-800 border-purple-200';
      case 'MAIN_QUERY': return 'bg-emerald-100 text-emerald-800 border-emerald-200';
      case 'SUBQUERY': return 'bg-amber-100 text-amber-800 border-amber-200';
      default: return 'bg-gray-100 text-gray-800 border-gray-200';
    }
  };

  return (
    <div className="h-full flex flex-col bg-white overflow-hidden">
      {/* Header */}
      <div className="p-4 border-b border-gray-200 bg-gray-50/50">
        <div className="flex items-center justify-between mb-2">
          <span className={`px-2 py-0.5 rounded text-xs font-bold border ${getTypeStyle(node.type)}`}>
            {node.type}
          </span>
          <span className="text-gray-400 text-xs font-mono">{node.id}</span>
        </div>
        <h2 className="text-lg font-bold text-gray-900 mb-2 leading-tight">{node.label}</h2>
        <p className="text-sm text-gray-600">{node.explanation}</p>
      </div>

      {/* Content */}
      <div className="flex-1 overflow-y-auto p-4 custom-scrollbar bg-gray-50/30">

        <div className="space-y-1">

          {/* Columns */}
          {node.ast.columns.length > 0 && (
            <DetailSection title="字段 Projections" defaultOpen={true}>
              <div className="grid grid-cols-1 gap-2">
                {node.ast.columns.map((col, idx) => (
                  <div key={idx} className="p-2 bg-gray-50 border border-gray-100 rounded text-sm flex flex-col hover:border-blue-200 transition-colors">
                    <span className="font-bold text-gray-800">{col.name}</span>
                    {col.expression && col.expression !== col.name && (
                      <div className="flex items-center gap-1 mt-1 text-xs text-gray-500 font-mono bg-gray-100/50 p-1 rounded w-fit">
                        <span className="text-gray-400">fn:</span>
                        {col.expression}
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </DetailSection>
          )}

          {/* Sources */}
          {node.ast.sources.length > 0 && (
            <DetailSection title="来源 Sources (From)" defaultOpen={true}>
              {node.ast.sources.map((src, idx) => (
                <div key={idx} className="flex items-center justify-between p-2 bg-blue-50 border border-blue-100 rounded text-sm">
                  <span className="font-semibold text-blue-900">{src.table}</span>
                  {src.alias && (
                    <span className="px-1.5 py-0.5 bg-blue-100 text-blue-600 rounded text-xs font-mono">
                      AS {src.alias}
                    </span>
                  )}
                </div>
              ))}
            </DetailSection>
          )}

          {/* Joins */}
          {node.ast.joins.length > 0 && (
            <DetailSection title="连接 Joins" defaultOpen={true}>
              {node.ast.joins.map((join, idx) => (
                <div key={idx} className="relative pl-3 border-l-2 border-gray-300 py-1 mb-1 last:mb-0">
                   <div className="flex items-center gap-2 mb-1">
                      <span className="text-xs font-bold uppercase text-gray-500 bg-gray-100 px-1 rounded">{join.type} JOIN</span>
                      <span className="font-bold text-gray-800 text-sm">{join.table}</span>
                   </div>
                   <div className="text-xs font-mono text-gray-600 bg-gray-50 p-1.5 rounded border border-gray-100 break-all">
                      ON {join.condition}
                   </div>
                </div>
              ))}
            </DetailSection>
          )}

          {/* Conditions */}
          {node.ast.conditions.length > 0 && (
             <DetailSection title="条件 Conditions" defaultOpen={false}>
               {node.ast.conditions.map((cond, idx) => (
                 <div key={idx} className="px-2 py-1.5 bg-yellow-50 border border-yellow-100 rounded text-sm text-yellow-900 font-mono break-words">
                   {cond}
                 </div>
               ))}
             </DetailSection>
          )}

          {/* Group By / Order By */}
          {(node.ast.groupBy?.length ?? 0) > 0 && (
             <DetailSection title="分组 Group By" defaultOpen={false}>
                <div className="flex flex-wrap gap-2">
                   {node.ast.groupBy?.map((g, i) => (
                      <span key={i} className="px-2 py-1 bg-gray-100 rounded text-xs font-mono text-gray-700">{g}</span>
                   ))}
                </div>
             </DetailSection>
          )}

           {(node.ast.orderBy?.length ?? 0) > 0 && (
             <DetailSection title="排序 Order By" defaultOpen={false}>
                <div className="flex flex-wrap gap-2">
                   {node.ast.orderBy?.map((o, i) => (
                      <span key={i} className="px-2 py-1 bg-gray-100 rounded text-xs font-mono text-gray-700">{o}</span>
                   ))}
                </div>
             </DetailSection>
          )}

        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useRef, useState } from 'react';
import * as d3 from 'd3';
import { SqlNode } from '../types';

interface QueryVisualizerProps {
  nodes: SqlNode[];
  onNodeSelect: (node: SqlNode) => void;
  selectedNodeId?: string;
}

interface TreeData extends SqlNode {
  children?: TreeData[];
}

// Helper for consistent colors
const getNodeStyles = (type: string) => {
  switch (type) {
    case 'ROOT': return { solid: "#dc2626", soft: "#fef2f2", text: "#b91c1c" }; // Red-600, Red-50
    case 'CTE': return { solid: "#9333ea", soft: "#faf5ff", text: "#7e22ce" }; // Purple-600, Purple-50
    case 'MAIN_QUERY': return { solid: "#059669", soft: "#ecfdf5", text: "#047857" }; // Emerald-600, Emerald-50
    case 'SUBQUERY': return { solid: "#d97706", soft: "#fffbeb", text: "#b45309" }; // Amber-600, Amber-50
    default: return { solid: "#4b5563", soft: "#f3f4f6", text: "#374151" }; // Gray-600, Gray-50
  }
};

export const QueryVisualizer: React.FC<QueryVisualizerProps> = ({ nodes, onNodeSelect, selectedNodeId }) => {
  const svgRef = useRef<SVGSVGElement>(null);
  const wrapperRef = useRef<HTMLDivElement>(null);
  const zoomRef = useRef<d3.ZoomBehavior<SVGSVGElement, unknown> | null>(null);
  const [dimensions, setDimensions] = useState({ width: 800, height: 600 });
  const [hasRendered, setHasRendered] = useState(false);

  useEffect(() => {
    const handleResize = () => {
      if (wrapperRef.current) {
        const { width, height } = wrapperRef.current.getBoundingClientRect();
        setDimensions({ width, height });
      }
    };
    window.addEventListener('resize', handleResize);
    handleResize(); 
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // --- Zoom Controls ---
  const handleZoomIn = () => {
    if (svgRef.current && zoomRef.current) {
      d3.select(svgRef.current)
        .transition()
        .duration(300)
        .call(zoomRef.current.scaleBy, 1.2);
    }
  };

  const handleZoomOut = () => {
    if (svgRef.current && zoomRef.current) {
      d3.select(svgRef.current)
        .transition()
        .duration(300)
        .call(zoomRef.current.scaleBy, 0.8);
    }
  };

  const handleReset = () => {
    // We re-trigger the initial zoom calculation logic by forcing a re-render or calling logic directly
    // Ideally we just want to run the "Zoom to Fit" logic again.
    // The easiest way with the current cleanup structure is to let the Effect dependency trigger, 
    // but that requires state change. Instead, I'll extract the fit logic or just set hasRendered to false briefly.
    setHasRendered(false);
  };

  useEffect(() => {
    if (!nodes.length || !svgRef.current) return;

    const svg = d3.select(svgRef.current);
    svg.selectAll("*").remove(); // Clear previous

    // --- Data Preparation ---
    const dataMap = new Map<string, TreeData>();
    nodes.forEach(node => dataMap.set(node.id, { ...node, children: [] }));

    let rootNode: TreeData | null = null;
    nodes.forEach(node => {
      if (node.parentId && dataMap.has(node.parentId)) {
        dataMap.get(node.parentId)!.children!.push(dataMap.get(node.id)!);
      } else {
        if (!rootNode || node.type === 'ROOT') {
          rootNode = dataMap.get(node.id)!;
        }
      }
    });

    if (!rootNode) return;

    // --- Configuration ---
    const nodeWidth = 240;
    const nodeHeight = 90;
    const horizontalSpacing = 60;
    const verticalSpacing = 100;

    // --- Tree Layout (Vertical) ---
    const hierarchy = d3.hierarchy<TreeData>(rootNode);

    const treeLayout = d3.tree<TreeData>()
      .nodeSize([nodeWidth + horizontalSpacing, nodeHeight + verticalSpacing])
      .separation((a, b) => a.parent === b.parent ? 1.1 : 1.3);

    const root = treeLayout(hierarchy);

    // --- Grid Background (Dot Pattern) ---
    const defs = svg.append("defs");
    const pattern = defs.append("pattern")
        .attr("id", "grid")
        .attr("width", 20)
        .attr("height", 20)
        .attr("patternUnits", "userSpaceOnUse");
    pattern.append("circle")
        .attr("cx", 2)
        .attr("cy", 2)
        .attr("r", 1)
        .attr("fill", "#e5e7eb");

    svg.append("rect")
       .attr("width", "100%")
       .attr("height", "100%")
       .attr("fill", "url(#grid)")
       .style("pointer-events", "none");

    // --- Zoom & Pan Setup ---
    const g = svg.append("g");

    const zoom = d3.zoom<SVGSVGElement, unknown>()
      .scaleExtent([0.1, 3])
      .on("zoom", (event) => {
        g.attr("transform", event.transform);
      });

    zoomRef.current = zoom;
    svg.call(zoom);

    // --- Draw Links ---
    g.selectAll(".link")
      .data(root.links())
      .enter().append("path")
      .attr("class", "link")
      .attr("fill", "none")
      .attr("stroke", "#9ca3af") // Gray-400
      .attr("stroke-width", 2)
      .attr("d", d3.linkVertical()
        .x((d: any) => d.x)
        .y((d: any) => d.y) as any
      );

    // --- Draw Nodes ---
    const nodeGroup = g.selectAll(".node")
      .data(root.descendants())
      .enter().append("g")
      .attr("class", "node")
      .attr("transform", d => `translate(${d.x},${d.y})`)
      .style("cursor", "pointer")
      .on("click", (event, d) => {
        onNodeSelect(d.data);
      });

    // 1. Node Card Background (Rect)
    nodeGroup.append("rect")
      .attr("width", nodeWidth)
      .attr("height", nodeHeight)
      .attr("x", -nodeWidth / 2)
      .attr("y", 0) 
      .attr("rx", 8)
      .style("transition", "fill 0.2s ease, stroke 0.2s ease, filter 0.2s ease") 
      .attr("fill", d => {
        const isSelected = d.data.id === selectedNodeId;
        const styles = getNodeStyles(d.data.type);
        return isSelected ? styles.solid : "#ffffff";
      })
      .attr("stroke", d => {
        const styles = getNodeStyles(d.data.type);
        return styles.solid;
      })
      .attr("stroke-width", 2)
      .style("filter", d => d.data.id === selectedNodeId 
        ? "drop-shadow(0px 8px 16px rgba(0,0,0,0.2))" 
        : "drop-shadow(0px 2px 4px rgba(0,0,0,0.1))"
      );

    // 2. Node Type Label (Badge)
    nodeGroup.append("rect")
      .attr("x", -nodeWidth / 2 + 10)
      .attr("y", 12)
      .attr("width", d => d.data.type.length * 7 + 10) 
      .attr("height", 18)
      .attr("rx", 4)
      .attr("fill", d => {
         const styles = getNodeStyles(d.data.type);
         return d.data.id === selectedNodeId ? "#ffffff" : styles.soft;
      });

    nodeGroup.append("text")
      .attr("x", -nodeWidth / 2 + 15)
      .attr("y", 24)
      .text(d => d.data.type)
      .style("font-size", "10px")
      .style("font-weight", "bold")
      .style("fill", d => {
         const styles = getNodeStyles(d.data.type);
         return styles.text; 
      });

    // 3. Main Label
    nodeGroup.append("text")
      .attr("x", -nodeWidth / 2 + 12)
      .attr("y", 48) 
      .text(d => {
        const str = d.data.label;
        return str.length > 25 ? str.substring(0, 25) + "..." : str;
      })
      .style("font-size", "14px")
      .style("font-weight", "bold")
      .style("fill", d => d.data.id === selectedNodeId ? "#ffffff" : "#111827");

    // 4. Explanation Snippet
    nodeGroup.append("text")
      .attr("x", -nodeWidth / 2 + 12)
      .attr("y", 68)
      .text(d => {
         const str = d.data.explanation || "";
         return str.length > 35 ? str.substring(0, 35) + "..." : str;
      })
      .style("font-size", "11px")
      .style("fill", d => d.data.id === selectedNodeId ? "rgba(255,255,255,0.9)" : "#6b7280");

    // --- Initial Zoom to Fit/Center ---
    // Only run this if we are rendering for the first time or explicitly reset (via hasRendered toggling)
    if (!hasRendered || dimensions.width > 0) { 
       let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
       root.descendants().forEach(d => {
         minX = Math.min(minX, d.x - nodeWidth/2);
         maxX = Math.max(maxX, d.x + nodeWidth/2);
         minY = Math.min(minY, d.y);
         maxY = Math.max(maxY, d.y + nodeHeight);
       });

       const treeWidth = maxX - minX;
       const treeHeight = maxY - minY;

       // Add some padding
       const paddingX = 100;
       const paddingY = 100;

       const availableWidth = dimensions.width - paddingX;
       const availableHeight = dimensions.height - paddingY;

       let scale = Math.min(
         1.2, 
         Math.min(availableWidth / treeWidth, availableHeight / treeHeight)
       );

       if (!isFinite(scale)) scale = 0.5;

       const initialTransform = d3.zoomIdentity
         .translate(
           (dimensions.width - treeWidth * scale) / 2 - minX * scale, 
           (dimensions.height - treeHeight * scale) / 2 - minY * scale + 40
         )
         .scale(scale);

       svg.call(zoom.transform, initialTransform);
       setHasRendered(true);
    }

  }, [nodes, dimensions, selectedNodeId, onNodeSelect, hasRendered]);

  return (
    <div ref={wrapperRef} className="w-full h-full bg-gray-50 rounded-lg overflow-hidden relative border border-gray-200 shadow-inner group">

      {/* Legend */}
      <div className="absolute top-4 left-4 text-xs text-gray-500 pointer-events-none z-10 flex flex-col gap-1 p-2 bg-white/80 rounded border border-gray-100 shadow-sm backdrop-blur-sm">
        <div className="flex items-center gap-2"><span className="w-3 h-3 rounded bg-purple-600"></span> CTE (Definition)</div>
        <div className="flex items-center gap-2"><span className="w-3 h-3 rounded bg-emerald-600"></span> Main Query</div>
        <div className="flex items-center gap-2"><span className="w-3 h-3 rounded bg-amber-600"></span> Subquery (Nested)</div>
      </div>

      {/* Zoom Controls */}
      <div className="absolute bottom-4 right-4 flex flex-col gap-2 z-10">
        <button 
          onClick={handleZoomIn}
          className="w-8 h-8 flex items-center justify-center bg-white border border-gray-200 rounded shadow hover:bg-gray-50 text-gray-700 font-bold text-lg"
          title="Zoom In"
        >
          +
        </button>
        <button 
          onClick={handleReset}
          className="w-8 h-8 flex items-center justify-center bg-white border border-gray-200 rounded shadow hover:bg-gray-50 text-gray-700"
          title="Fit to Screen"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 0l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5l-5-5m5 5v-4m0 4h-4"></path></svg>
        </button>
        <button 
          onClick={handleZoomOut}
          className="w-8 h-8 flex items-center justify-center bg-white border border-gray-200 rounded shadow hover:bg-gray-50 text-gray-700 font-bold text-lg"
          title="Zoom Out"
        >
          -
        </button>
      </div>

      <svg ref={svgRef} width="100%" height="100%"></svg>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { analyzeSql } from './services/geminiService';
import { AnalysisResult, QueryStatus, SqlNode } from './types';
import { QueryVisualizer } from './components/QueryVisualizer';
import { AstInspector } from './components/AstInspector';

// Example complex query for initial state
const DEFAULT_QUERY = `
WITH RegionalSales AS (
    SELECT region, SUM(amount) as total_sales
    FROM sales
    JOIN locations ON sales.location_id = locations.id
    WHERE sales.date > '2023-01-01'
    GROUP BY region
),
TopRegions AS (
    SELECT region
    FROM RegionalSales
    WHERE total_sales > 1000000
)
SELECT 
    e.employee_name,
    r.region,
    COUNT(o.id) as order_count
FROM employees e
JOIN orders o ON e.id = o.employee_id
JOIN TopRegions r ON e.region = r.region
WHERE o.status = 'completed'
GROUP BY e.employee_name, r.region
ORDER BY order_count DESC;
`;

const App: React.FC = () => {
  const [sqlInput, setSqlInput] = useState<string>(DEFAULT_QUERY.trim());
  const [status, setStatus] = useState<QueryStatus>(QueryStatus.IDLE);
  const [data, setData] = useState<AnalysisResult | null>(null);
  const [selectedNode, setSelectedNode] = useState<SqlNode | null>(null);
  const [errorMsg, setErrorMsg] = useState<string>("");

  // Refs for synced scrolling
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const backdropRef = useRef<HTMLDivElement>(null);

  // Layout State
  const [sidebarWidth, setSidebarWidth] = useState(320);
  const [inspectorWidth, setInspectorWidth] = useState(300);
  const [isResizingSidebar, setIsResizingSidebar] = useState(false);
  const [isResizingInspector, setIsResizingInspector] = useState(false);

  // Resize Handlers
  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (isResizingSidebar) {
        setSidebarWidth(Math.max(250, Math.min(600, e.clientX)));
      }
      if (isResizingInspector) {
        // Inspector is now the middle panel.
        // e.clientX represents the right edge of the Inspector panel.
        // We calculate width by subtracting the sidebar width (left edge of Inspector).
        const newWidth = e.clientX - sidebarWidth;
        setInspectorWidth(Math.max(250, Math.min(800, newWidth)));
      }
    };

    const handleMouseUp = () => {
      setIsResizingSidebar(false);
      setIsResizingInspector(false);
      document.body.style.cursor = 'default';
    };

    if (isResizingSidebar || isResizingInspector) {
      document.addEventListener('mousemove', handleMouseMove);
      document.addEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = 'col-resize';
    }

    return () => {
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = 'default';
    };
  }, [isResizingSidebar, isResizingInspector, sidebarWidth]);

  // Sync scroll between textarea and backdrop
  const handleScroll = () => {
    if (textareaRef.current && backdropRef.current) {
      backdropRef.current.scrollTop = textareaRef.current.scrollTop;
      backdropRef.current.scrollLeft = textareaRef.current.scrollLeft;
    }
  };

  // Scroll to highlight when selection changes
  useEffect(() => {
    if (selectedNode && textareaRef.current) {
      const snippet = selectedNode.sqlSnippet;
      if (!snippet) return;

      let startIdx = sqlInput.indexOf(snippet);
      if (startIdx === -1) {
        startIdx = sqlInput.indexOf(snippet.trim());
      }

      if (startIdx !== -1) {
        // We still focus the textarea so keyboard works immediately
        textareaRef.current.focus();
        // Determine line number to scroll to roughly
        const textBefore = sqlInput.substring(0, startIdx);
        const linesBefore = textBefore.split('\n').length;
        const lineHeight = 20; // Approx line height in px for text-sm

        // Smooth scroll the textarea (which syncs the backdrop via onScroll)
        textareaRef.current.scrollTo({
          top: (linesBefore - 2) * lineHeight, 
          behavior: 'smooth'
        });
      }
    }
  }, [selectedNode]);

  const handleAnalyze = async () => {
    if (!sqlInput.trim()) return;

    setStatus(QueryStatus.LOADING);
    setErrorMsg("");
    setSelectedNode(null);

    try {
      const result = await analyzeSql(sqlInput);
      setData(result);

      // Default to MAIN_QUERY if available, otherwise ROOT
      const defaultNode = result.nodes.find(n => n.type === 'MAIN_QUERY') || result.nodes.find(n => n.type === 'ROOT');
      if (defaultNode) setSelectedNode(defaultNode);

      setStatus(QueryStatus.SUCCESS);
    } catch (err: any) {
      console.error(err);
      setErrorMsg(err.message || "Failed to analyze SQL. Please check your API key or input.");
      setStatus(QueryStatus.ERROR);
    }
  };

  // Render the highlighted text for the backdrop
  const renderHighlightedText = () => {
    if (!selectedNode || !selectedNode.sqlSnippet) {
      return <span className="text-gray-800">{sqlInput}</span>;
    }

    const snippet = selectedNode.sqlSnippet;
    let startIdx = sqlInput.indexOf(snippet);
    let matchLength = snippet.length;

    if (startIdx === -1) {
      const trimmed = snippet.trim();
      startIdx = sqlInput.indexOf(trimmed);
      matchLength = trimmed.length;
    }

    if (startIdx === -1) return <span className="text-gray-800">{sqlInput}</span>;

    const before = sqlInput.substring(0, startIdx);
    const match = sqlInput.substring(startIdx, startIdx + matchLength);
    const after = sqlInput.substring(startIdx + matchLength);

    return (
      <>
        <span className="text-gray-400 opacity-50 transition-opacity duration-300">{before}</span>
        <span className="bg-blue-100 text-blue-900 rounded border-b-2 border-blue-500 font-bold shadow-sm px-0.5 box-decoration-clone">
          {match}
        </span>
        <span className="text-gray-400 opacity-50 transition-opacity duration-300">{after}</span>
      </>
    );
  };

  return (
    <div className="flex h-screen w-full bg-white text-gray-900 font-sans overflow-hidden">

      {/* 1. Sidebar: Input (Resizable) */}
      <div 
        style={{ width: sidebarWidth }} 
        className="flex-shrink-0 flex flex-col border-r border-gray-200 bg-gray-50 transition-colors"
      >
        <div className="p-4 border-b border-gray-200 flex justify-between items-center bg-white">
          <div className="flex items-center gap-2">
            <div className="w-3 h-3 rounded-full bg-blue-600"></div>
            <h1 className="text-lg font-bold text-gray-800 tracking-tight">SQL Vision</h1>
          </div>
          <button 
            onClick={handleAnalyze}
            disabled={status === QueryStatus.LOADING}
            className={`px-4 py-1.5 rounded text-sm font-semibold transition-all shadow-sm ${
              status === QueryStatus.LOADING 
              ? 'bg-gray-100 text-gray-400 cursor-wait' 
              : 'bg-blue-600 hover:bg-blue-700 text-white shadow-blue-500/20'
            }`}
          >
            {status === QueryStatus.LOADING ? 'Analyzing...' : 'Visualize'}
          </button>
        </div>

        {/* Custom Layered Editor (Light Mode) */}
        <div className="flex-1 relative group overflow-hidden bg-white">

          {/* Layer 1: Backdrop (Presentation) */}
          <div 
            ref={backdropRef}
            className="absolute inset-0 p-4 font-mono text-sm whitespace-pre-wrap break-words overflow-auto pointer-events-none z-0 custom-scrollbar"
            style={{ fontFamily: 'Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace', lineHeight: '1.6' }}
          >
            {renderHighlightedText()}
            {/* Add extra space at bottom to match textarea behavior */}
            <div className="h-8"></div> 
          </div>

          {/* Layer 2: Textarea (Interaction) */}
          <textarea 
            ref={textareaRef}
            value={sqlInput}
            onChange={(e) => setSqlInput(e.target.value)}
            onScroll={handleScroll}
            className="absolute inset-0 w-full h-full p-4 font-mono text-sm whitespace-pre-wrap break-words bg-transparent text-transparent caret-blue-600 resize-none focus:outline-none z-10 custom-scrollbar selection:bg-blue-100 selection:text-blue-900"
            style={{ fontFamily: 'Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace', lineHeight: '1.6' }}
            spellCheck={false}
            placeholder="Paste your complex SQL query here..."
          />
        </div>

        {status === QueryStatus.ERROR && (
          <div className="p-4 bg-red-50 border-t border-red-200 text-red-700 text-sm">
            <strong>Error:</strong> {errorMsg}
          </div>
        )}
      </div>

      {/* Resizer Handle 1 (Left) */}
      <div 
        className="w-1 cursor-col-resize hover:bg-blue-400 bg-gray-200 transition-colors z-20 flex-shrink-0"
        onMouseDown={() => setIsResizingSidebar(true)}
      />

      {/* 2. Middle: Inspector (Resizable) - MOVED HERE */}
      <div 
        style={{ width: inspectorWidth }} 
        className="flex-shrink-0 border-r border-gray-200 bg-white z-10 flex flex-col"
      >
        <AstInspector node={selectedNode} />
      </div>

      {/* Resizer Handle 2 (Right) - MOVED HERE */}
      <div 
        className="w-1 cursor-col-resize hover:bg-blue-400 bg-gray-200 transition-colors z-20 flex-shrink-0"
        onMouseDown={() => setIsResizingInspector(true)}
      />

      {/* 3. Main Content: Graph Area (Light Mode) - MOVED HERE */}
      <div className="flex-1 flex flex-col relative bg-gray-50 overflow-hidden">
        {/* Graph Area */}
        <div className="flex-1 relative">
          {data ? (
            <QueryVisualizer 
              nodes={data.nodes} 
              onNodeSelect={setSelectedNode}
              selectedNodeId={selectedNode?.id}
            />
          ) : (
             <div className="absolute inset-0 flex flex-col items-center justify-center text-gray-400">
               {status === QueryStatus.LOADING ? (
                 <div className="flex flex-col items-center">
                   <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mb-4"></div>
                   <p className="text-gray-600 font-medium">Processing AST with Gemini AI...</p>
                 </div>
               ) : (
                 <>
                   <svg className="w-24 h-24 mb-4 opacity-10 text-gray-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19.428 15.428a2 2 0 00-1.022-.547l-2.384-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z"></path></svg>
                   <p className="text-gray-400">Enter a query and click Visualize to generate the Query Map.</p>
                 </>
               )}
             </div>
          )}
        </div>
      </div>

    </div>
  );
};

export default App;

import React, { useEffect, useRef, useState } from 'react';
import * as d3 from 'd3';
import { SqlNode } from '../types';

interface QueryVisualizerProps {
  nodes: SqlNode[];
  onNodeSelect: (node: SqlNode) => void;
  selectedNodeId?: string;
}

interface TreeData extends SqlNode {
  children?: TreeData[];
}

// Helper for consistent colors
const getNodeStyles = (type: string) => {
  switch (type) {
    case 'ROOT': return { solid: "#dc2626", soft: "#fef2f2", text: "#b91c1c" }; // Red-600, Red-50
    case 'CTE': return { solid: "#9333ea", soft: "#faf5ff", text: "#7e22ce" }; // Purple-600, Purple-50
    case 'MAIN_QUERY': return { solid: "#059669", soft: "#ecfdf5", text: "#047857" }; // Emerald-600, Emerald-50
    case 'SUBQUERY': return { solid: "#d97706", soft: "#fffbeb", text: "#b45309" }; // Amber-600, Amber-50
    default: return { solid: "#4b5563", soft: "#f3f4f6", text: "#374151" }; // Gray-600, Gray-50
  }
};

export const QueryVisualizer: React.FC<QueryVisualizerProps> = ({ nodes, onNodeSelect, selectedNodeId }) => {
  const svgRef = useRef<SVGSVGElement>(null);
  const wrapperRef = useRef<HTMLDivElement>(null);
  const zoomRef = useRef<d3.ZoomBehavior<SVGSVGElement, unknown> | null>(null);
  const [dimensions, setDimensions] = useState({ width: 800, height: 600 });
  const [hasRendered, setHasRendered] = useState(false);

  useEffect(() => {
    const handleResize = () => {
      if (wrapperRef.current) {
        const { width, height } = wrapperRef.current.getBoundingClientRect();
        setDimensions({ width, height });
      }
    };
    window.addEventListener('resize', handleResize);
    handleResize(); 
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // --- Zoom Controls ---
  const handleZoomIn = () => {
    if (svgRef.current && zoomRef.current) {
      d3.select(svgRef.current)
        .transition()
        .duration(300)
        .call(zoomRef.current.scaleBy, 1.2);
    }
  };

  const handleZoomOut = () => {
    if (svgRef.current && zoomRef.current) {
      d3.select(svgRef.current)
        .transition()
        .duration(300)
        .call(zoomRef.current.scaleBy, 0.8);
    }
  };

  const handleReset = () => {
    setHasRendered(false);
  };

  useEffect(() => {
    if (!nodes.length || !svgRef.current) return;

    const svg = d3.select(svgRef.current);
    svg.selectAll("*").remove(); // Clear previous

    // --- Data Preparation ---
    const dataMap = new Map<string, TreeData>();
    nodes.forEach(node => dataMap.set(node.id, { ...node, children: [] }));

    let rootNode: TreeData | null = null;
    nodes.forEach(node => {
      if (node.parentId && dataMap.has(node.parentId)) {
        dataMap.get(node.parentId)!.children!.push(dataMap.get(node.id)!);
      } else {
        if (!rootNode || node.type === 'ROOT') {
          rootNode = dataMap.get(node.id)!;
        }
      }
    });

    if (!rootNode) return;

    // --- Configuration ---
    const nodeWidth = 220;
    const nodeHeight = 60; // Reduced height since explanation is removed
    const horizontalSpacing = 40;
    const verticalSpacing = 80;

    // --- Tree Layout (Vertical) ---
    const hierarchy = d3.hierarchy<TreeData>(rootNode);

    const treeLayout = d3.tree<TreeData>()
      .nodeSize([nodeWidth + horizontalSpacing, nodeHeight + verticalSpacing])
      .separation((a, b) => a.parent === b.parent ? 1.1 : 1.3);

    const root = treeLayout(hierarchy);

    // --- Grid Background (Dot Pattern) ---
    const defs = svg.append("defs");
    const pattern = defs.append("pattern")
        .attr("id", "grid")
        .attr("width", 20)
        .attr("height", 20)
        .attr("patternUnits", "userSpaceOnUse");
    pattern.append("circle")
        .attr("cx", 2)
        .attr("cy", 2)
        .attr("r", 1)
        .attr("fill", "#e5e7eb");

    svg.append("rect")
       .attr("width", "100%")
       .attr("height", "100%")
       .attr("fill", "url(#grid)")
       .style("pointer-events", "none");

    // --- Zoom & Pan Setup ---
    const g = svg.append("g");

    const zoom = d3.zoom<SVGSVGElement, unknown>()
      .scaleExtent([0.1, 3])
      .on("zoom", (event) => {
        g.attr("transform", event.transform);
      });

    zoomRef.current = zoom;
    svg.call(zoom);

    // --- Draw Links ---
    g.selectAll(".link")
      .data(root.links())
      .enter().append("path")
      .attr("class", "link")
      .attr("fill", "none")
      .attr("stroke", "#9ca3af") // Gray-400
      .attr("stroke-width", 2)
      .attr("d", d3.linkVertical()
        .x((d: any) => d.x)
        .y((d: any) => d.y) as any
      );

    // --- Draw Nodes ---
    const nodeGroup = g.selectAll(".node")
      .data(root.descendants())
      .enter().append("g")
      .attr("class", "node")
      .attr("transform", d => `translate(${d.x},${d.y})`)
      .style("cursor", "pointer")
      .on("click", (event, d) => {
        onNodeSelect(d.data);
      });

    // 1. Node Card Background (Rect)
    nodeGroup.append("rect")
      .attr("width", nodeWidth)
      .attr("height", nodeHeight)
      .attr("x", -nodeWidth / 2)
      .attr("y", 0) 
      .attr("rx", 6)
      .style("transition", "fill 0.2s ease, stroke 0.2s ease, filter 0.2s ease") 
      .attr("fill", d => {
        const isSelected = d.data.id === selectedNodeId;
        const styles = getNodeStyles(d.data.type);
        return isSelected ? styles.solid : "#ffffff";
      })
      .attr("stroke", d => {
        const styles = getNodeStyles(d.data.type);
        return styles.solid;
      })
      .attr("stroke-width", 2)
      .style("filter", d => d.data.id === selectedNodeId 
        ? "drop-shadow(0px 8px 16px rgba(0,0,0,0.2))" 
        : "drop-shadow(0px 2px 4px rgba(0,0,0,0.1))"
      );

    // 2. Node Type Label (Badge)
    nodeGroup.append("rect")
      .attr("x", -nodeWidth / 2 + 10)
      .attr("y", 10)
      .attr("width", d => d.data.type.length * 7 + 10) 
      .attr("height", 16)
      .attr("rx", 4)
      .attr("fill", d => {
         const styles = getNodeStyles(d.data.type);
         return d.data.id === selectedNodeId ? "#ffffff" : styles.soft;
      });

    nodeGroup.append("text")
      .attr("x", -nodeWidth / 2 + 15)
      .attr("y", 21)
      .text(d => d.data.type)
      .style("font-size", "9px")
      .style("font-weight", "bold")
      .style("fill", d => {
         const styles = getNodeStyles(d.data.type);
         return styles.text; 
      });

    // 3. Main Label
    nodeGroup.append("text")
      .attr("x", -nodeWidth / 2 + 12)
      .attr("y", 42) 
      .text(d => {
        const str = d.data.label;
        return str.length > 30 ? str.substring(0, 30) + "..." : str;
      })
      .style("font-size", "13px")
      .style("font-weight", "bold")
      .style("fill", d => d.data.id === selectedNodeId ? "#ffffff" : "#111827");

    // Explanation removed as requested

    // --- Initial Zoom to Fit/Center ---
    if (!hasRendered || dimensions.width > 0) { 
       let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
       root.descendants().forEach(d => {
         minX = Math.min(minX, d.x - nodeWidth/2);
         maxX = Math.max(maxX, d.x + nodeWidth/2);
         minY = Math.min(minY, d.y);
         maxY = Math.max(maxY, d.y + nodeHeight);
       });

       const treeWidth = maxX - minX;
       const treeHeight = maxY - minY;

       // Add some padding
       const paddingX = 100;
       const paddingY = 100;

       const availableWidth = dimensions.width - paddingX;
       const availableHeight = dimensions.height - paddingY;

       let scale = Math.min(
         1.2, 
         Math.min(availableWidth / treeWidth, availableHeight / treeHeight)
       );

       if (!isFinite(scale)) scale = 0.5;

       const initialTransform = d3.zoomIdentity
         .translate(
           (dimensions.width - treeWidth * scale) / 2 - minX * scale, 
           (dimensions.height - treeHeight * scale) / 2 - minY * scale + 40
         )
         .scale(scale);

       svg.call(zoom.transform, initialTransform);
       setHasRendered(true);
    }

  }, [nodes, dimensions, selectedNodeId, onNodeSelect, hasRendered]);

  return (
    <div ref={wrapperRef} className="w-full h-full bg-gray-50 rounded-lg overflow-hidden relative border border-gray-200 shadow-inner group">

      {/* Legend */}
      <div className="absolute top-4 left-4 text-xs text-gray-500 pointer-events-none z-10 flex flex-col gap-1 p-2 bg-white/80 rounded border border-gray-100 shadow-sm backdrop-blur-sm">
        <div className="flex items-center gap-2"><span className="w-3 h-3 rounded bg-purple-600"></span> CTE (Definition)</div>
        <div className="flex items-center gap-2"><span className="w-3 h-3 rounded bg-emerald-600"></span> Main Query</div>
        <div className="flex items-center gap-2"><span className="w-3 h-3 rounded bg-amber-600"></span> Subquery (Nested)</div>
      </div>

      {/* Zoom Controls */}
      <div className="absolute bottom-4 right-4 flex flex-col gap-2 z-10">
        <button 
          onClick={handleZoomIn}
          className="w-8 h-8 flex items-center justify-center bg-white border border-gray-200 rounded shadow hover:bg-gray-50 text-gray-700 font-bold text-lg"
          title="Zoom In"
        >
          +
        </button>
        <button 
          onClick={handleReset}
          className="w-8 h-8 flex items-center justify-center bg-white border border-gray-200 rounded shadow hover:bg-gray-50 text-gray-700"
          title="Fit to Screen"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 0l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5l-5-5m5 5v-4m0 4h-4"></path></svg>
        </button>
        <button 
          onClick={handleZoomOut}
          className="w-8 h-8 flex items-center justify-center bg-white border border-gray-200 rounded shadow hover:bg-gray-50 text-gray-700 font-bold text-lg"
          title="Zoom Out"
        >
          -
        </button>
      </div>

      <svg ref={svgRef} width="100%" height="100%"></svg>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { analyzeSql } from './services/geminiService';
import { AnalysisResult, QueryStatus, SqlNode } from './types';
import { QueryVisualizer } from './components/QueryVisualizer';
import { AstInspector } from './components/AstInspector';

// Example complex query for initial state
const DEFAULT_QUERY = `
WITH RegionalSales AS (
    SELECT region, SUM(amount) as total_sales
    FROM sales
    JOIN locations ON sales.location_id = locations.id
    WHERE sales.date > '2023-01-01'
    GROUP BY region
),
TopRegions AS (
    SELECT region
    FROM RegionalSales
    WHERE total_sales > 1000000
)
SELECT 
    e.employee_name,
    r.region,
    COUNT(o.id) as order_count
FROM employees e
JOIN orders o ON e.id = o.employee_id
JOIN TopRegions r ON e.region = r.region
WHERE o.status = 'completed'
GROUP BY e.employee_name, r.region
ORDER BY order_count DESC;
`;

const App: React.FC = () => {
  const [sqlInput, setSqlInput] = useState<string>(DEFAULT_QUERY.trim());
  const [status, setStatus] = useState<QueryStatus>(QueryStatus.IDLE);
  const [data, setData] = useState<AnalysisResult | null>(null);
  const [selectedNode, setSelectedNode] = useState<SqlNode | null>(null);
  const [errorMsg, setErrorMsg] = useState<string>("");

  // Refs for synced scrolling
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const backdropRef = useRef<HTMLDivElement>(null);

  // Layout State
  // Default to 1/4 width for Sidebar and Inspector, leaving 1/2 for Visualization
  const [sidebarWidth, setSidebarWidth] = useState(() => typeof window !== 'undefined' ? window.innerWidth / 4 : 320);
  const [inspectorWidth, setInspectorWidth] = useState(() => typeof window !== 'undefined' ? window.innerWidth / 4 : 320);

  const [isResizingSidebar, setIsResizingSidebar] = useState(false);
  const [isResizingInspector, setIsResizingInspector] = useState(false);

  // Resize Handlers
  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (isResizingSidebar) {
        setSidebarWidth(Math.max(250, Math.min(600, e.clientX)));
      }
      if (isResizingInspector) {
        // Inspector is now the middle panel.
        // e.clientX represents the right edge of the Inspector panel.
        // We calculate width by subtracting the sidebar width (left edge of Inspector).
        const newWidth = e.clientX - sidebarWidth;
        setInspectorWidth(Math.max(250, Math.min(800, newWidth)));
      }
    };

    const handleMouseUp = () => {
      setIsResizingSidebar(false);
      setIsResizingInspector(false);
      document.body.style.cursor = 'default';
    };

    if (isResizingSidebar || isResizingInspector) {
      document.addEventListener('mousemove', handleMouseMove);
      document.addEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = 'col-resize';
    }

    return () => {
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
      document.body.style.cursor = 'default';
    };
  }, [isResizingSidebar, isResizingInspector, sidebarWidth]);

  // Sync scroll between textarea and backdrop
  const handleScroll = () => {
    if (textareaRef.current && backdropRef.current) {
      backdropRef.current.scrollTop = textareaRef.current.scrollTop;
      backdropRef.current.scrollLeft = textareaRef.current.scrollLeft;
    }
  };

  // Scroll to highlight when selection changes
  useEffect(() => {
    if (selectedNode && textareaRef.current) {
      const snippet = selectedNode.sqlSnippet;
      if (!snippet) return;

      let startIdx = sqlInput.indexOf(snippet);
      if (startIdx === -1) {
        startIdx = sqlInput.indexOf(snippet.trim());
      }

      if (startIdx !== -1) {
        // We still focus the textarea so keyboard works immediately
        textareaRef.current.focus();
        // Determine line number to scroll to roughly
        const textBefore = sqlInput.substring(0, startIdx);
        const linesBefore = textBefore.split('\n').length;
        const lineHeight = 20; // Approx line height in px for text-sm

        // Smooth scroll the textarea (which syncs the backdrop via onScroll)
        textareaRef.current.scrollTo({
          top: (linesBefore - 2) * lineHeight, 
          behavior: 'smooth'
        });
      }
    }
  }, [selectedNode]);

  const handleAnalyze = async () => {
    if (!sqlInput.trim()) return;

    setStatus(QueryStatus.LOADING);
    setErrorMsg("");
    setSelectedNode(null);

    try {
      const result = await analyzeSql(sqlInput);
      setData(result);

      // Default to MAIN_QUERY if available, otherwise ROOT
      const defaultNode = result.nodes.find(n => n.type === 'MAIN_QUERY') || result.nodes.find(n => n.type === 'ROOT');
      if (defaultNode) setSelectedNode(defaultNode);

      setStatus(QueryStatus.SUCCESS);
    } catch (err: any) {
      console.error(err);
      setErrorMsg(err.message || "Failed to analyze SQL. Please check your API key or input.");
      setStatus(QueryStatus.ERROR);
    }
  };

  // Render the highlighted text for the backdrop
  const renderHighlightedText = () => {
    if (!selectedNode || !selectedNode.sqlSnippet) {
      return <span className="text-gray-800">{sqlInput}</span>;
    }

    const snippet = selectedNode.sqlSnippet;
    let startIdx = sqlInput.indexOf(snippet);
    let matchLength = snippet.length;

    if (startIdx === -1) {
      const trimmed = snippet.trim();
      startIdx = sqlInput.indexOf(trimmed);
      matchLength = trimmed.length;
    }

    if (startIdx === -1) return <span className="text-gray-800">{sqlInput}</span>;

    const before = sqlInput.substring(0, startIdx);
    const match = sqlInput.substring(startIdx, startIdx + matchLength);
    const after = sqlInput.substring(startIdx + matchLength);

    return (
      <>
        <span className="text-gray-400 opacity-50 transition-opacity duration-300">{before}</span>
        <span className="bg-blue-100 text-blue-900 rounded border-b-2 border-blue-500 font-bold shadow-sm px-0.5 box-decoration-clone">
          {match}
        </span>
        <span className="text-gray-400 opacity-50 transition-opacity duration-300">{after}</span>
      </>
    );
  };

  return (
    <div className="flex h-screen w-full bg-white text-gray-900 font-sans overflow-hidden">

      {/* 1. Sidebar: Input (Resizable) */}
      <div 
        style={{ width: sidebarWidth }} 
        className="flex-shrink-0 flex flex-col border-r border-gray-200 bg-gray-50 transition-colors"
      >
        <div className="p-4 border-b border-gray-200 flex justify-between items-center bg-white">
          <div className="flex items-center gap-2">
            <div className="w-3 h-3 rounded-full bg-blue-600"></div>
            <h1 className="text-lg font-bold text-gray-800 tracking-tight">SQL Vision</h1>
          </div>
          <button 
            onClick={handleAnalyze}
            disabled={status === QueryStatus.LOADING}
            className={`px-4 py-1.5 rounded text-sm font-semibold transition-all shadow-sm ${
              status === QueryStatus.LOADING 
              ? 'bg-gray-100 text-gray-400 cursor-wait' 
              : 'bg-blue-600 hover:bg-blue-700 text-white shadow-blue-500/20'
            }`}
          >
            {status === QueryStatus.LOADING ? 'Analyzing...' : 'Visualize'}
          </button>
        </div>

        {/* Custom Layered Editor (Light Mode) */}
        <div className="flex-1 relative group overflow-hidden bg-white">

          {/* Layer 1: Backdrop (Presentation) */}
          <div 
            ref={backdropRef}
            className="absolute inset-0 p-4 font-mono text-sm whitespace-pre-wrap break-words overflow-auto pointer-events-none z-0 custom-scrollbar"
            style={{ fontFamily: 'Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace', lineHeight: '1.6' }}
          >
            {renderHighlightedText()}
            {/* Add extra space at bottom to match textarea behavior */}
            <div className="h-8"></div> 
          </div>

          {/* Layer 2: Textarea (Interaction) */}
          <textarea 
            ref={textareaRef}
            value={sqlInput}
            onChange={(e) => setSqlInput(e.target.value)}
            onScroll={handleScroll}
            className="absolute inset-0 w-full h-full p-4 font-mono text-sm whitespace-pre-wrap break-words bg-transparent text-transparent caret-blue-600 resize-none focus:outline-none z-10 custom-scrollbar selection:bg-blue-100 selection:text-blue-900"
            style={{ fontFamily: 'Menlo, Monaco, Consolas, "Liberation Mono", "Courier New", monospace', lineHeight: '1.6' }}
            spellCheck={false}
            placeholder="Paste your complex SQL query here..."
          />
        </div>

        {status === QueryStatus.ERROR && (
          <div className="p-4 bg-red-50 border-t border-red-200 text-red-700 text-sm">
            <strong>Error:</strong> {errorMsg}
          </div>
        )}
      </div>

      {/* Resizer Handle 1 (Left) */}
      <div 
        className="w-1 cursor-col-resize hover:bg-blue-400 bg-gray-200 transition-colors z-20 flex-shrink-0"
        onMouseDown={() => setIsResizingSidebar(true)}
      />

      {/* 2. Middle: Inspector (Resizable) - MOVED HERE */}
      <div 
        style={{ width: inspectorWidth }} 
        className="flex-shrink-0 border-r border-gray-200 bg-white z-10 flex flex-col"
      >
        <AstInspector node={selectedNode} />
      </div>

      {/* Resizer Handle 2 (Right) - MOVED HERE */}
      <div 
        className="w-1 cursor-col-resize hover:bg-blue-400 bg-gray-200 transition-colors z-20 flex-shrink-0"
        onMouseDown={() => setIsResizingInspector(true)}
      />

      {/* 3. Main Content: Graph Area (Light Mode) - MOVED HERE */}
      <div className="flex-1 flex flex-col relative bg-gray-50 overflow-hidden">
        {/* Graph Area */}
        <div className="flex-1 relative">
          {data ? (
            <QueryVisualizer 
              nodes={data.nodes} 
              onNodeSelect={setSelectedNode}
              selectedNodeId={selectedNode?.id}
            />
          ) : (
             <div className="absolute inset-0 flex flex-col items-center justify-center text-gray-400">
               {status === QueryStatus.LOADING ? (
                 <div className="flex flex-col items-center">
                   <div className="w-12 h-12 border-4 border-blue-600 border-t-transparent rounded-full animate-spin mb-4"></div>
                   <p className="text-gray-600 font-medium">Processing AST with Gemini AI...</p>
                 </div>
               ) : (
                 <>
                   <svg className="w-24 h-24 mb-4 opacity-10 text-gray-300" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19.428 15.428a2 2 0 00-1.022-.547l-2.384-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z"></path></svg>
                   <p className="text-gray-400">Enter a query and click Visualize to generate the Query Map.</p>
                 </>
               )}
             </div>
          )}
        </div>
      </div>

    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { SqlNode, AstColumn, AstSource, AstJoin } from '../types';

interface AstInspectorProps {
  node: SqlNode | null;
}

const DetailSection: React.FC<{ title: string; children: React.ReactNode; defaultOpen?: boolean }> = ({ title, children, defaultOpen = true }) => {
  const [isOpen, setIsOpen] = useState(defaultOpen);

  if (!children) return null;
  // If children is an array and empty, don't render
  if (Array.isArray(children) && children.length === 0) return null;

  return (
    <div className="border border-gray-200 rounded-lg overflow-hidden bg-white shadow-sm mb-3">
      <button 
        onClick={() => setIsOpen(!isOpen)}
        className="w-full flex items-center justify-between p-3 bg-gray-50 hover:bg-gray-100 transition-colors text-left"
      >
        <span className="text-xs uppercase tracking-wider text-gray-600 font-bold flex items-center gap-2">
          {title}
        </span>
        <svg 
          className={`w-4 h-4 text-gray-400 transition-transform duration-200 ${isOpen ? 'transform rotate-180' : ''}`} 
          fill="none" 
          stroke="currentColor" 
          viewBox="0 0 24 24"
        >
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" />
        </svg>
      </button>

      {isOpen && (
        <div className="p-3 bg-white border-t border-gray-100 flex flex-col gap-2 animate-in slide-in-from-top-1 duration-200">
          {children}
        </div>
      )}
    </div>
  );
};

export const AstInspector: React.FC<AstInspectorProps> = ({ node }) => {
  if (!node) {
    return (
      <div className="h-full flex items-center justify-center text-gray-500 p-8 text-center bg-white">
        <p>在图表中选择一个节点以查看其抽象语法树 (AST)。</p>
      </div>
    );
  }

  const getTypeStyle = (type: string) => {
    switch (type) {
      case 'ROOT': return 'bg-red-100 text-red-800 border-red-200';
      case 'CTE': return 'bg-purple-100 text-purple-800 border-purple-200';
      case 'MAIN_QUERY': return 'bg-emerald-100 text-emerald-800 border-emerald-200';
      case 'SUBQUERY': return 'bg-amber-100 text-amber-800 border-amber-200';
      default: return 'bg-gray-100 text-gray-800 border-gray-200';
    }
  };

  return (
    <div className="h-full flex flex-col bg-white overflow-hidden">
      {/* Header */}
      <div className="p-4 border-b border-gray-200 bg-gray-50/50">
        <div className="flex items-center justify-between mb-2">
          <span className={`px-2 py-0.5 rounded text-xs font-bold border ${getTypeStyle(node.type)}`}>
            {node.type}
          </span>
          <span className="text-gray-400 text-xs font-mono">{node.id}</span>
        </div>
        <h2 className="text-lg font-bold text-gray-900 mb-2 leading-tight">{node.label}</h2>
        <p className="text-sm text-gray-600">{node.explanation}</p>
      </div>

      {/* Content */}
      <div className="flex-1 overflow-y-auto p-4 custom-scrollbar bg-gray-50/30">

        <div className="space-y-1">

          {/* Columns */}
          {node.ast.columns.length > 0 && (
            <DetailSection title="字段 Projections" defaultOpen={true}>
              <div className="grid grid-cols-1 gap-2">
                {node.ast.columns.map((col, idx) => (
                  <div key={idx} className="p-2 bg-gray-50 border border-gray-100 rounded text-sm flex flex-col hover:border-blue-200 transition-colors">
                    <span className="font-bold text-gray-800">{col.name}</span>
                    {col.expression && col.expression !== col.name && (
                      <div className="flex items-center gap-1 mt-1 text-xs text-gray-500 font-mono bg-gray-100/50 p-1 rounded w-fit">
                        <span className="text-gray-400">fn:</span>
                        {col.expression}
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </DetailSection>
          )}

          {/* Combined Sources & Joins */}
          {(node.ast.sources.length > 0 || node.ast.joins.length > 0) && (
            <DetailSection title="来源与连接 Sources & Joins" defaultOpen={true}>

              {/* Sources List */}
              {node.ast.sources.length > 0 && (
                 <div className="flex flex-col gap-2">
                   {node.ast.sources.map((src, idx) => (
                    <div key={`src-${idx}`} className="flex items-center justify-between p-2 bg-blue-50 border border-blue-100 rounded text-sm">
                      <span className="font-semibold text-blue-900">{src.table}</span>
                      {src.alias && (
                        <span className="px-1.5 py-0.5 bg-blue-100 text-blue-600 rounded text-xs font-mono">
                          AS {src.alias}
                        </span>
                      )}
                    </div>
                  ))}
                 </div>
              )}

              {/* Separator if both exist */}
              {node.ast.sources.length > 0 && node.ast.joins.length > 0 && (
                 <div className="my-1 border-t border-gray-100"></div>
              )}

              {/* Joins List */}
              {node.ast.joins.length > 0 && (
                 <div className="flex flex-col gap-1">
                   {node.ast.joins.map((join, idx) => (
                    <div key={`join-${idx}`} className="relative pl-3 border-l-2 border-gray-300 py-1 mb-1 last:mb-0">
                       <div className="flex items-center gap-2 mb-1">
                          <span className="text-xs font-bold uppercase text-gray-500 bg-gray-100 px-1 rounded">{join.type} JOIN</span>
                          <span className="font-bold text-gray-800 text-sm">{join.table}</span>
                       </div>
                       <div className="text-xs font-mono text-gray-600 bg-gray-50 p-1.5 rounded border border-gray-100 break-all">
                          ON {join.condition}
                       </div>
                    </div>
                  ))}
                 </div>
              )}
            </DetailSection>
          )}

          {/* Conditions */}
          {node.ast.conditions.length > 0 && (
             <DetailSection title="条件 Conditions" defaultOpen={false}>
               {node.ast.conditions.map((cond, idx) => (
                 <div key={idx} className="px-2 py-1.5 bg-yellow-50 border border-yellow-100 rounded text-sm text-yellow-900 font-mono break-words">
                   {cond}
                 </div>
               ))}
             </DetailSection>
          )}

          {/* Group By / Order By */}
          {(node.ast.groupBy?.length ?? 0) > 0 && (
             <DetailSection title="分组 Group By" defaultOpen={false}>
                <div className="flex flex-wrap gap-2">
                   {node.ast.groupBy?.map((g, i) => (
                      <span key={i} className="px-2 py-1 bg-gray-100 rounded text-xs font-mono text-gray-700">{g}</span>
                   ))}
                </div>
             </DetailSection>
          )}

           {(node.ast.orderBy?.length ?? 0) > 0 && (
             <DetailSection title="排序 Order By" defaultOpen={false}>
                <div className="flex flex-wrap gap-2">
                   {node.ast.orderBy?.map((o, i) => (
                      <span key={i} className="px-2 py-1 bg-gray-100 rounded text-xs font-mono text-gray-700">{o}</span>
                   ))}
                </div>
             </DetailSection>
          )}

        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useRef, useState } from 'react';
import * as d3 from 'd3';
import { SqlNode } from '../types';

interface QueryVisualizerProps {
  nodes: SqlNode[];
  onNodeSelect: (node: SqlNode) => void;
  selectedNodeId?: string;
}

interface TreeData extends SqlNode {
  children?: TreeData[];
}

// Helper for consistent colors
const getNodeStyles = (type: string) => {
  switch (type) {
    case 'ROOT': return { solid: "#dc2626", soft: "#fef2f2", text: "#b91c1c" }; // Red-600, Red-50
    case 'CTE': return { solid: "#9333ea", soft: "#faf5ff", text: "#7e22ce" }; // Purple-600, Purple-50
    case 'MAIN_QUERY': return { solid: "#059669", soft: "#ecfdf5", text: "#047857" }; // Emerald-600, Emerald-50
    case 'SUBQUERY': return { solid: "#d97706", soft: "#fffbeb", text: "#b45309" }; // Amber-600, Amber-50
    default: return { solid: "#4b5563", soft: "#f3f4f6", text: "#374151" }; // Gray-600, Gray-50
  }
};

export const QueryVisualizer: React.FC<QueryVisualizerProps> = ({ nodes, onNodeSelect, selectedNodeId }) => {
  const svgRef = useRef<SVGSVGElement>(null);
  const wrapperRef = useRef<HTMLDivElement>(null);
  const zoomRef = useRef<d3.ZoomBehavior<SVGSVGElement, unknown> | null>(null);
  const [dimensions, setDimensions] = useState({ width: 800, height: 600 });
  const [hasRendered, setHasRendered] = useState(false);

  useEffect(() => {
    const handleResize = () => {
      if (wrapperRef.current) {
        const { width, height } = wrapperRef.current.getBoundingClientRect();
        setDimensions({ width, height });
      }
    };
    window.addEventListener('resize', handleResize);
    handleResize(); 
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // --- Zoom Controls ---
  const handleZoomIn = () => {
    if (svgRef.current && zoomRef.current) {
      d3.select(svgRef.current)
        .transition()
        .duration(300)
        .call(zoomRef.current.scaleBy, 1.2);
    }
  };

  const handleZoomOut = () => {
    if (svgRef.current && zoomRef.current) {
      d3.select(svgRef.current)
        .transition()
        .duration(300)
        .call(zoomRef.current.scaleBy, 0.8);
    }
  };

  const handleReset = () => {
    setHasRendered(false);
  };

  useEffect(() => {
    if (!nodes.length || !svgRef.current) return;

    const svg = d3.select(svgRef.current);
    svg.selectAll("*").remove(); // Clear previous

    // --- Data Preparation ---
    const dataMap = new Map<string, TreeData>();
    nodes.forEach(node => dataMap.set(node.id, { ...node, children: [] }));

    let rootNode: TreeData | null = null;
    nodes.forEach(node => {
      if (node.parentId && dataMap.has(node.parentId)) {
        dataMap.get(node.parentId)!.children!.push(dataMap.get(node.id)!);
      } else {
        if (!rootNode || node.type === 'ROOT') {
          rootNode = dataMap.get(node.id)!;
        }
      }
    });

    if (!rootNode) return;

    // --- Configuration ---
    const nodeWidth = 220;
    const nodeHeight = 60; // Reduced height since explanation is removed
    const horizontalSpacing = 40;
    const verticalSpacing = 80;

    // --- Tree Layout (Vertical) ---
    const hierarchy = d3.hierarchy<TreeData>(rootNode);

    const treeLayout = d3.tree<TreeData>()
      .nodeSize([nodeWidth + horizontalSpacing, nodeHeight + verticalSpacing])
      .separation((a, b) => a.parent === b.parent ? 1.1 : 1.3);

    const root = treeLayout(hierarchy);

    // --- Grid Background (Dot Pattern) ---
    const defs = svg.append("defs");
    const pattern = defs.append("pattern")
        .attr("id", "grid")
        .attr("width", 20)
        .attr("height", 20)
        .attr("patternUnits", "userSpaceOnUse");
    pattern.append("circle")
        .attr("cx", 2)
        .attr("cy", 2)
        .attr("r", 1)
        .attr("fill", "#e5e7eb");

    svg.append("rect")
       .attr("width", "100%")
       .attr("height", "100%")
       .attr("fill", "url(#grid)")
       .style("pointer-events", "none");

    // --- Zoom & Pan Setup ---
    const g = svg.append("g");

    const zoom = d3.zoom<SVGSVGElement, unknown>()
      .scaleExtent([0.1, 3])
      .on("zoom", (event) => {
        g.attr("transform", event.transform);
      });

    zoomRef.current = zoom;
    svg.call(zoom);

    // --- Draw Links ---
    g.selectAll(".link")
      .data(root.links())
      .enter().append("path")
      .attr("class", "link")
      .attr("fill", "none")
      .attr("stroke", "#9ca3af") // Gray-400
      .attr("stroke-width", 2)
      .attr("d", d3.linkVertical()
        .x((d: any) => d.x)
        .y((d: any) => d.y) as any
      );

    // --- Draw Nodes ---
    const nodeGroup = g.selectAll(".node")
      .data(root.descendants())
      .enter().append("g")
      .attr("class", "node")
      .attr("transform", d => `translate(${d.x},${d.y})`)
      .style("cursor", "pointer")
      .on("click", (event, d) => {
        onNodeSelect(d.data);
      });

    // 1. Node Card Background (Rect)
    nodeGroup.append("rect")
      .attr("width", nodeWidth)
      .attr("height", nodeHeight)
      .attr("x", -nodeWidth / 2)
      .attr("y", 0) 
      .attr("rx", 6)
      .style("transition", "fill 0.2s ease, stroke 0.2s ease, filter 0.2s ease") 
      .attr("fill", d => {
        const isSelected = d.data.id === selectedNodeId;
        const styles = getNodeStyles(d.data.type);
        return isSelected ? styles.solid : "#ffffff";
      })
      .attr("stroke", d => {
        const styles = getNodeStyles(d.data.type);
        return styles.solid;
      })
      .attr("stroke-width", 2)
      .style("filter", d => d.data.id === selectedNodeId 
        ? "drop-shadow(0px 8px 16px rgba(0,0,0,0.2))" 
        : "drop-shadow(0px 2px 4px rgba(0,0,0,0.1))"
      );

    // 2. Node Type Label (Badge)
    nodeGroup.append("rect")
      .attr("x", -nodeWidth / 2 + 10)
      .attr("y", 10)
      .attr("width", d => d.data.type.length * 7 + 10) 
      .attr("height", 16)
      .attr("rx", 4)
      .attr("fill", d => {
         const styles = getNodeStyles(d.data.type);
         return d.data.id === selectedNodeId ? "#ffffff" : styles.soft;
      });

    nodeGroup.append("text")
      .attr("x", -nodeWidth / 2 + 15)
      .attr("y", 21)
      .text(d => d.data.type)
      .style("font-size", "9px")
      .style("font-weight", "bold")
      .style("fill", d => {
         const styles = getNodeStyles(d.data.type);
         return styles.text; 
      });

    // 3. Main Label
    nodeGroup.append("text")
      .attr("x", -nodeWidth / 2 + 12)
      .attr("y", 42) 
      .text(d => {
        const str = d.data.label;
        return str.length > 30 ? str.substring(0, 30) + "..." : str;
      })
      .style("font-size", "13px")
      .style("font-weight", "bold")
      .style("fill", d => d.data.id === selectedNodeId ? "#ffffff" : "#111827");

    // Explanation removed as requested

    // --- Initial Zoom to Fit/Center ---
    if (!hasRendered || dimensions.width > 0) { 
       let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
       root.descendants().forEach(d => {
         minX = Math.min(minX, d.x - nodeWidth/2);
         maxX = Math.max(maxX, d.x + nodeWidth/2);
         minY = Math.min(minY, d.y);
         maxY = Math.max(maxY, d.y + nodeHeight);
       });

       const treeWidth = maxX - minX;
       const treeHeight = maxY - minY;

       // Add some padding
       const paddingX = 100;
       const paddingY = 100;

       const availableWidth = dimensions.width - paddingX;
       const availableHeight = dimensions.height - paddingY;

       let scale = Math.min(
         1.2, 
         Math.min(availableWidth / treeWidth, availableHeight / treeHeight)
       );

       if (!isFinite(scale)) scale = 0.5;

       const initialTransform = d3.zoomIdentity
         .translate(
           (dimensions.width - treeWidth * scale) / 2 - minX * scale, 
           (dimensions.height - treeHeight * scale) / 2 - minY * scale + 40
         )
         .scale(scale);

       svg.call(zoom.transform, initialTransform);
       setHasRendered(true);
    }

  }, [nodes, dimensions, selectedNodeId, onNodeSelect, hasRendered]);

  return (
    <div ref={wrapperRef} className="w-full h-full bg-gray-50 rounded-lg overflow-hidden relative border border-gray-200 shadow-inner group">

      {/* Legend */}
      <div className="absolute top-4 left-4 text-xs text-gray-500 pointer-events-none z-10 flex flex-col gap-1 p-2 bg-white/80 rounded border border-gray-100 shadow-sm backdrop-blur-sm">
        <div className="flex items-center gap-2"><span className="w-3 h-3 rounded bg-purple-600"></span> CTE (Definition)</div>
        <div className="flex items-center gap-2"><span className="w-3 h-3 rounded bg-emerald-600"></span> Main Query</div>
        <div className="flex items-center gap-2"><span className="w-3 h-3 rounded bg-amber-600"></span> Subquery (Nested)</div>
      </div>

      {/* Zoom Controls */}
      <div className="absolute bottom-4 right-4 flex flex-col gap-2 z-10">
        <button 
          onClick={handleZoomIn}
          className="w-8 h-8 flex items-center justify-center bg-white border border-gray-200 rounded shadow hover:bg-gray-50 text-gray-700 font-bold text-lg"
          title="Zoom In"
        >
          +
        </button>
        <button 
          onClick={handleReset}
          className="w-8 h-8 flex items-center justify-center bg-white border border-gray-200 rounded shadow hover:bg-gray-50 text-gray-700"
          title="Fit to Screen"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 0l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5l-5-5m5 5v-4m0 4h-4"></path></svg>
        </button>
        <button 
          onClick={handleZoomOut}
          className="w-8 h-8 flex items-center justify-center bg-white border border-gray-200 rounded shadow hover:bg-gray-50 text-gray-700 font-bold text-lg"
          title="Zoom Out"
        >
          -
        </button>
      </div>

      <svg ref={svgRef} width="100%" height="100%"></svg>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
