          {/* Group By / Order By */}
          {(node.ast.groupBy?.length ?? 0) > 0 && (
             <DetailSection title="分组 Group By" defaultOpen={false}>
                <div className="flex flex-wrap gap-2">
                   {node.ast.groupBy?.map((g, i) => (
                      <span key={i} className="px-2 py-1 bg-gray-100 rounded text-xs font-mono text-gray-700">{g}</span>
                   ))}
                </div>
             </DetailSection>
          )}

           {(node.ast.orderBy?.length ?? 0) > 0 && (
             <DetailSection title="排序 Order By" defaultOpen={false}>
                <div className="flex flex-wrap gap-2">
                   {node.ast.orderBy?.map((o, i) => (
                      <span key={i} className="px-2 py-1 bg-gray-100 rounded text-xs font-mono text-gray-700">{o}</span>
                   ))}
                </div>
             </DetailSection>
          )}

        </div>
      </div>
    </div>
  );
};

export interface AstSource {
  table: string;
  alias?: string;
}

export interface AstColumn {
  name: string;       // The output name (alias or column name)
  expression: string; // The underlying logic/calculation
}

export interface AstJoin {
  type: string; // INNER, LEFT, etc.
  table: string; // The table being joined
  condition: string; // The ON clause
}

export interface AstDetails {
  columns: AstColumn[];
  sources: AstSource[]; 
  joins: AstJoin[];
  conditions: string[]; // Where/Having clauses
  groupBy?: string[];
  orderBy?: string[];
}

export interface SqlNode {
  id: string;
  label: string; // Short name e.g. "Main Query", "Subquery A"
  type: 'ROOT' | 'CTE_BLOCK' | 'CTE' | 'MAIN_QUERY' | 'SUBQUERY' | 'UNION' | 'JOIN_PART';
  sqlSnippet: string;
  explanation: string;
  parentId?: string | null; // For tree construction
  ast: AstDetails;
  alias?: string; // The alias of this node in the parent query (e.g. "t1")
}

export interface AnalysisResult {
  nodes: SqlNode[];
}

export enum QueryStatus {
  IDLE = 'IDLE',
  LOADING = 'LOADING',
  SUCCESS = 'SUCCESS',
  ERROR = 'ERROR'
}

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const SYSTEM_INSTRUCTION = `
You are an expert SQL parser and visualizer backend. 
Your task is to analyze the SYNTACTIC structure of a SQL query and return a hierarchical tree of nodes.

**LANGUAGE REQUIREMENT:**
- The **structure** (keys like id, type, ast) must remain in English.
- The **content** for 'label' and 'explanation' MUST be in **Simplified Chinese (简体中文)**.

**CRITICAL RULES FOR HIERARCHY:**
1. **Root Node**: Represents the entire SQL file/input.
2. **CTE Definitions**: If the query uses a WITH clause, each CTE (Common Table Expression) definition must be a DIRECT CHILD of the Root Node.
   - **IMPORTANT**: Even if "CTE_B" selects from "CTE_A", treat them as SIBLING definitions in the WITH block. Do NOT nest CTEs inside each other. They are parallel definitions.
3. **Main Query**: The primary SELECT/INSERT/UPDATE statement is a sibling of the CTEs (child of Root).
4. **Subqueries**: Any SELECT statement nested physically inside a FROM, JOIN, WHERE, HAVING, or Projection clause must be a CHILD of the node containing it.
   - Example: "SELECT * FROM (SELECT ...) t1" -> The inner SELECT is a child of the outer SELECT.
   - **Alias Extraction**: If a subquery is aliased (e.g., "... ) t1"), you MUST extract "t1" into the 'alias' field.

**Output Schema Requirements:**
For each node, provide:
- **id**: Unique string.
- **label**: Short name in Chinese (e.g., "主查询", "区域销售CTE", "子查询 t1").
- **type**: One of ['ROOT', 'CTE', 'MAIN_QUERY', 'SUBQUERY', 'UNION', 'JOIN_PART'].
- **alias**: The alias string if this block is a subquery or CTE (e.g. "t1", "my_table"). Null otherwise.
- **parentId**: The ID of the syntactic container node.
- **sqlSnippet**: The EXACT character-for-character substring.
- **ast**: Extract key details:
  - **columns**: Array of objects { name: "output_name", expression: "formula_or_source" }.
  - **sources**: Array of objects { table: "table_name", alias: "alias_if_exists" }.
  - **joins**: Array of objects { type: "INNER/LEFT", table: "target_table", condition: "on_clause" }.
  - **conditions**: Simple string array of WHERE/HAVING clauses.
`;

export const analyzeSql = async (sql: string): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Analyze this SQL query structure:\n\n${sql}`,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            nodes: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING, description: "Unique ID like 'node_1'" },
                  label: { type: Type.STRING, description: "Human readable label in Chinese" },
                  type: { type: Type.STRING, enum: ['ROOT', 'CTE', 'MAIN_QUERY', 'SUBQUERY', 'UNION', 'JOIN_PART'] },
                  alias: { type: Type.STRING, description: "The alias of the subquery/CTE in the parent query (e.g. 't1')", nullable: true },
                  sqlSnippet: { type: Type.STRING, description: "The EXACT source code substring for this block" },
                  explanation: { type: Type.STRING, description: "Brief explanation of what this block does in Chinese" },
                  parentId: { type: Type.STRING, description: "ID of the parent node. Null if Root.", nullable: true },
                  ast: {
                    type: Type.OBJECT,
                    properties: {
                      columns: { 
                        type: Type.ARRAY, 
                        items: { 
                          type: Type.OBJECT,
                          properties: {
                            name: { type: Type.STRING, description: "The alias or output column name" },
                            expression: { type: Type.STRING, description: "The original expression or column, e.g. SUM(amount)" }
                          },
                          required: ["name", "expression"]
                        } 
                      },
                      sources: { 
                        type: Type.ARRAY, 
                        items: { 
                          type: Type.OBJECT,
                          properties: {
                            table: { type: Type.STRING },
                            alias: { type: Type.STRING, nullable: true }
                          },
                          required: ["table"]
                        } 
                      },
                      joins: { 
                        type: Type.ARRAY, 
                        items: { 
                          type: Type.OBJECT,
                          properties: {
                            type: { type: Type.STRING },
                            table: { type: Type.STRING },
                            condition: { type: Type.STRING }
                          },
                          required: ["type", "table", "condition"]
                        } 
                      },
                      conditions: { type: Type.ARRAY, items: { type: Type.STRING } },
                      groupBy: { type: Type.ARRAY, items: { type: Type.STRING } },
                      orderBy: { type: Type.ARRAY, items: { type: Type.STRING } },
                    },
                    required: ["columns", "sources", "joins", "conditions"]
                  }
                },
                required: ["id", "label", "type", "sqlSnippet", "explanation", "ast"]
              }
            }
          },
          required: ["nodes"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as AnalysisResult;

  } catch (error) {
    console.error("Gemini Analysis Failed:", error);
    throw error;
  }
};

import React, { useEffect, useRef, useState } from 'react';
import * as d3 from 'd3';
import { SqlNode } from '../types';

interface QueryVisualizerProps {
  nodes: SqlNode[];
  onNodeSelect: (node: SqlNode) => void;
  selectedNodeId?: string;
}

interface TreeData extends SqlNode {
  children?: TreeData[];
}

// Helper for consistent colors
const getNodeStyles = (type: string) => {
  switch (type) {
    case 'ROOT': return { solid: "#dc2626", soft: "#fef2f2", text: "#b91c1c" }; // Red-600, Red-50
    case 'CTE': return { solid: "#9333ea", soft: "#faf5ff", text: "#7e22ce" }; // Purple-600, Purple-50
    case 'MAIN_QUERY': return { solid: "#059669", soft: "#ecfdf5", text: "#047857" }; // Emerald-600, Emerald-50
    case 'SUBQUERY': return { solid: "#d97706", soft: "#fffbeb", text: "#b45309" }; // Amber-600, Amber-50
    default: return { solid: "#4b5563", soft: "#f3f4f6", text: "#374151" }; // Gray-600, Gray-50
  }
};

export const QueryVisualizer: React.FC<QueryVisualizerProps> = ({ nodes, onNodeSelect, selectedNodeId }) => {
  const svgRef = useRef<SVGSVGElement>(null);
  const wrapperRef = useRef<HTMLDivElement>(null);
  const zoomRef = useRef<d3.ZoomBehavior<SVGSVGElement, unknown> | null>(null);
  const [dimensions, setDimensions] = useState({ width: 800, height: 600 });
  const [hasRendered, setHasRendered] = useState(false);

  useEffect(() => {
    const handleResize = () => {
      if (wrapperRef.current) {
        const { width, height } = wrapperRef.current.getBoundingClientRect();
        setDimensions({ width, height });
      }
    };
    window.addEventListener('resize', handleResize);
    handleResize(); 
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // --- Zoom Controls ---
  const handleZoomIn = () => {
    if (svgRef.current && zoomRef.current) {
      d3.select(svgRef.current)
        .transition()
        .duration(300)
        .call(zoomRef.current.scaleBy, 1.2);
    }
  };

  const handleZoomOut = () => {
    if (svgRef.current && zoomRef.current) {
      d3.select(svgRef.current)
        .transition()
        .duration(300)
        .call(zoomRef.current.scaleBy, 0.8);
    }
  };

  const handleReset = () => {
    setHasRendered(false);
  };

  useEffect(() => {
    if (!nodes.length || !svgRef.current) return;

    const svg = d3.select(svgRef.current);
    svg.selectAll("*").remove(); // Clear previous

    // --- Data Preparation ---
    const dataMap = new Map<string, TreeData>();
    nodes.forEach(node => dataMap.set(node.id, { ...node, children: [] }));

    let rootNode: TreeData | null = null;
    nodes.forEach(node => {
      if (node.parentId && dataMap.has(node.parentId)) {
        dataMap.get(node.parentId)!.children!.push(dataMap.get(node.id)!);
      } else {
        if (!rootNode || node.type === 'ROOT') {
          rootNode = dataMap.get(node.id)!;
        }
      }
    });

    if (!rootNode) return;

    // --- Configuration ---
    const nodeWidth = 220;
    const nodeHeight = 60; // Reduced height since explanation is removed
    const horizontalSpacing = 40;
    const verticalSpacing = 80;

    // --- Tree Layout (Vertical) ---
    const hierarchy = d3.hierarchy<TreeData>(rootNode);

    const treeLayout = d3.tree<TreeData>()
      .nodeSize([nodeWidth + horizontalSpacing, nodeHeight + verticalSpacing])
      .separation((a, b) => a.parent === b.parent ? 1.1 : 1.3);

    const root = treeLayout(hierarchy);

    // --- Grid Background (Dot Pattern) ---
    const defs = svg.append("defs");
    const pattern = defs.append("pattern")
        .attr("id", "grid")
        .attr("width", 20)
        .attr("height", 20)
        .attr("patternUnits", "userSpaceOnUse");
    pattern.append("circle")
        .attr("cx", 2)
        .attr("cy", 2)
        .attr("r", 1)
        .attr("fill", "#e5e7eb");

    svg.append("rect")
       .attr("width", "100%")
       .attr("height", "100%")
       .attr("fill", "url(#grid)")
       .style("pointer-events", "none");

    // --- Zoom & Pan Setup ---
    const g = svg.append("g");

    const zoom = d3.zoom<SVGSVGElement, unknown>()
      .scaleExtent([0.1, 3])
      .on("zoom", (event) => {
        g.attr("transform", event.transform);
      });

    zoomRef.current = zoom;
    svg.call(zoom);

    // --- Draw Links ---
    g.selectAll(".link")
      .data(root.links())
      .enter().append("path")
      .attr("class", "link")
      .attr("fill", "none")
      .attr("stroke", "#9ca3af") // Gray-400
      .attr("stroke-width", 2)
      .attr("d", d3.linkVertical()
        .x((d: any) => d.x)
        .y((d: any) => d.y) as any
      );

    // --- Draw Nodes ---
    const nodeGroup = g.selectAll(".node")
      .data(root.descendants())
      .enter().append("g")
      .attr("class", "node")
      .attr("transform", d => `translate(${d.x},${d.y})`)
      .style("cursor", "pointer")
      .on("click", (event, d) => {
        onNodeSelect(d.data);
      });

    // 1. Node Card Background (Rect)
    nodeGroup.append("rect")
      .attr("width", nodeWidth)
      .attr("height", nodeHeight)
      .attr("x", -nodeWidth / 2)
      .attr("y", 0) 
      .attr("rx", 6)
      .style("transition", "fill 0.2s ease, stroke 0.2s ease, filter 0.2s ease") 
      .attr("fill", d => {
        const isSelected = d.data.id === selectedNodeId;
        const styles = getNodeStyles(d.data.type);
        return isSelected ? styles.solid : "#ffffff";
      })
      .attr("stroke", d => {
        const styles = getNodeStyles(d.data.type);
        return styles.solid;
      })
      .attr("stroke-width", 2)
      .style("filter", d => d.data.id === selectedNodeId 
        ? "drop-shadow(0px 8px 16px rgba(0,0,0,0.2))" 
        : "drop-shadow(0px 2px 4px rgba(0,0,0,0.1))"
      );

    // 2. Node Type Label (Badge)
    nodeGroup.append("rect")
      .attr("x", -nodeWidth / 2 + 10)
      .attr("y", 10)
      .attr("width", d => d.data.type.length * 7 + 10) 
      .attr("height", 16)
      .attr("rx", 4)
      .attr("fill", d => {
         const styles = getNodeStyles(d.data.type);
         return d.data.id === selectedNodeId ? "#ffffff" : styles.soft;
      });

    nodeGroup.append("text")
      .attr("x", -nodeWidth / 2 + 15)
      .attr("y", 21)
      .text(d => d.data.type)
      .style("font-size", "9px")
      .style("font-weight", "bold")
      .style("fill", d => {
         const styles = getNodeStyles(d.data.type);
         return styles.text; 
      });

    // 3. Alias Label (Right-aligned Badge) - Only if alias exists
    nodeGroup.each(function(d) {
        if (!d.data.alias) return;

        const g = d3.select(this);
        const aliasText = `AS ${d.data.alias}`;
        const charWidth = 6.5; // Approximate width per char for 9px font
        const width = Math.max(30, aliasText.length * charWidth + 10);
        const xPos = (nodeWidth / 2) - width - 10; // Right aligned

        // Background
        g.append("rect")
            .attr("x", xPos)
            .attr("y", 10)
            .attr("width", width)
            .attr("height", 16)
            .attr("rx", 4)
            .attr("fill", "#eff6ff") // blue-50
            .attr("stroke", "#bfdbfe"); // blue-200

        // Text
        g.append("text")
            .attr("x", xPos + width/2)
            .attr("y", 21)
            .attr("text-anchor", "middle")
            .text(aliasText)
            .style("font-size", "9px")
            .style("font-weight", "bold")
            .style("fill", "#1e40af"); // blue-800
    });

    // 4. Main Label
    nodeGroup.append("text")
      .attr("x", -nodeWidth / 2 + 12)
      .attr("y", 42) 
      .text(d => {
        const str = d.data.label;
        return str.length > 30 ? str.substring(0, 30) + "..." : str;
      })
      .style("font-size", "13px")
      .style("font-weight", "bold")
      .style("fill", d => d.data.id === selectedNodeId ? "#ffffff" : "#111827");

    // --- Initial Zoom to Fit/Center ---
    if (!hasRendered || dimensions.width > 0) { 
       let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
       root.descendants().forEach(d => {
         minX = Math.min(minX, d.x - nodeWidth/2);
         maxX = Math.max(maxX, d.x + nodeWidth/2);
         minY = Math.min(minY, d.y);
         maxY = Math.max(maxY, d.y + nodeHeight);
       });

       const treeWidth = maxX - minX;
       const treeHeight = maxY - minY;

       // Add some padding
       const paddingX = 100;
       const paddingY = 100;

       const availableWidth = dimensions.width - paddingX;
       const availableHeight = dimensions.height - paddingY;

       let scale = Math.min(
         1.2, 
         Math.min(availableWidth / treeWidth, availableHeight / treeHeight)
       );

       if (!isFinite(scale)) scale = 0.5;

       const initialTransform = d3.zoomIdentity
         .translate(
           (dimensions.width - treeWidth * scale) / 2 - minX * scale, 
           (dimensions.height - treeHeight * scale) / 2 - minY * scale + 40
         )
         .scale(scale);

       svg.call(zoom.transform, initialTransform);
       setHasRendered(true);
    }

  }, [nodes, dimensions, selectedNodeId, onNodeSelect, hasRendered]);

  return (
    <div ref={wrapperRef} className="w-full h-full bg-gray-50 rounded-lg overflow-hidden relative border border-gray-200 shadow-inner group">

      {/* Legend */}
      <div className="absolute top-4 left-4 text-xs text-gray-500 pointer-events-none z-10 flex flex-col gap-1 p-2 bg-white/80 rounded border border-gray-100 shadow-sm backdrop-blur-sm">
        <div className="flex items-center gap-2"><span className="w-3 h-3 rounded bg-purple-600"></span> CTE (Definition)</div>
        <div className="flex items-center gap-2"><span className="w-3 h-3 rounded bg-emerald-600"></span> Main Query</div>
        <div className="flex items-center gap-2"><span className="w-3 h-3 rounded bg-amber-600"></span> Subquery (Nested)</div>
      </div>

      {/* Zoom Controls */}
      <div className="absolute bottom-4 right-4 flex flex-col gap-2 z-10">
        <button 
          onClick={handleZoomIn}
          className="w-8 h-8 flex items-center justify-center bg-white border border-gray-200 rounded shadow hover:bg-gray-50 text-gray-700 font-bold text-lg"
          title="Zoom In"
        >
          +
        </button>
        <button 
          onClick={handleReset}
          className="w-8 h-8 flex items-center justify-center bg-white border border-gray-200 rounded shadow hover:bg-gray-50 text-gray-700"
          title="Fit to Screen"
        >
          <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 8V4m0 0h4M4 4l5 5m11-1V4m0 0h-4m4 0l-5 5M4 16v4m0 0h4m-4 0l5-5m11 5l-5-5m5 5v-4m0 4h-4"></path></svg>
        </button>
        <button 
          onClick={handleZoomOut}
          className="w-8 h-8 flex items-center justify-center bg-white border border-gray-200 rounded shadow hover:bg-gray-50 text-gray-700 font-bold text-lg"
          title="Zoom Out"
        >
          -
        </button>
      </div>

      <svg ref={svgRef} width="100%" height="100%"></svg>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { AnalysisResult } from "../types";

const SYSTEM_INSTRUCTION = `
You are an expert SQL parser and visualizer backend. 
Your task is to analyze the SYNTACTIC structure of a SQL query and return a hierarchical tree of nodes.

**LANGUAGE REQUIREMENT:**
- The **structure** (keys like id, type, ast) must remain in English.
- The **content** for 'label' and 'explanation' MUST be in **Simplified Chinese (简体中文)**.

**CRITICAL RULES FOR HIERARCHY:**
1. **Root Node**: Represents the entire SQL file/input.
2. **CTE Definitions**: If the query uses a WITH clause, each CTE (Common Table Expression) definition must be a DIRECT CHILD of the Root Node.
   - **IMPORTANT**: Even if "CTE_B" selects from "CTE_A", treat them as SIBLING definitions in the WITH block. Do NOT nest CTEs inside each other. They are parallel definitions.
3. **Main Query**: The primary SELECT/INSERT/UPDATE statement is a sibling of the CTEs (child of Root).
4. **Subqueries**: Any SELECT statement nested physically inside a FROM, JOIN, WHERE, HAVING, or Projection clause must be a CHILD of the node containing it.
   - Example: "SELECT * FROM (SELECT ...) t1" -> The inner SELECT is a child of the outer SELECT.
   - **Alias Extraction**: If a subquery is aliased (e.g., "... ) t1"), you MUST extract "t1" into the 'alias' field.

**IMPORTANT: SQL SNIPPET EXTRACTION**
- The \`sqlSnippet\` field MUST be the **EXACT** substring from the original code, preserving original whitespace, newlines, comments, and case.
- **DO NOT** reformat, pretty-print, or normalize the SQL in the snippet.
- **DO NOT** remove comments inside the snippet.

**Output Schema Requirements:**
For each node, provide:
- **id**: Unique string.
- **label**: Short name in Chinese (e.g., "主查询", "区域销售CTE", "子查询 t1").
- **type**: One of ['ROOT', 'CTE', 'MAIN_QUERY', 'SUBQUERY', 'UNION', 'JOIN_PART'].
- **alias**: The alias string if this block is a subquery or CTE (e.g. "t1", "my_table"). Null otherwise.
- **parentId**: The ID of the syntactic container node.
- **sqlSnippet**: The EXACT character-for-character substring from the source.
- **ast**: Extract key details:
  - **columns**: Array of objects { name: "output_name", expression: "formula_or_source" }.
  - **sources**: Array of objects { table: "table_name", alias: "alias_if_exists" }.
  - **joins**: Array of objects { type: "INNER/LEFT", table: "target_table", condition: "on_clause" }.
  - **conditions**: Simple string array of WHERE/HAVING clauses.
`;

export const analyzeSql = async (sql: string): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Analyze this SQL query structure:\n\n${sql}`,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            nodes: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.STRING, description: "Unique ID like 'node_1'" },
                  label: { type: Type.STRING, description: "Human readable label in Chinese" },
                  type: { type: Type.STRING, enum: ['ROOT', 'CTE', 'MAIN_QUERY', 'SUBQUERY', 'UNION', 'JOIN_PART'] },
                  alias: { type: Type.STRING, description: "The alias of the subquery/CTE in the parent query (e.g. 't1')", nullable: true },
                  sqlSnippet: { type: Type.STRING, description: "The EXACT source code substring for this block" },
                  explanation: { type: Type.STRING, description: "Brief explanation of what this block does in Chinese" },
                  parentId: { type: Type.STRING, description: "ID of the parent node. Null if Root.", nullable: true },
                  ast: {
                    type: Type.OBJECT,
                    properties: {
                      columns: { 
                        type: Type.ARRAY, 
                        items: { 
                          type: Type.OBJECT,
                          properties: {
                            name: { type: Type.STRING, description: "The alias or output column name" },
                            expression: { type: Type.STRING, description: "The original expression or column, e.g. SUM(amount)" }
                          },
                          required: ["name", "expression"]
                        } 
                      },
                      sources: { 
                        type: Type.ARRAY, 
                        items: { 
                          type: Type.OBJECT,
                          properties: {
                            table: { type: Type.STRING },
                            alias: { type: Type.STRING, nullable: true }
                          },
                          required: ["table"]
                        } 
                      },
                      joins: { 
                        type: Type.ARRAY, 
                        items: { 
                          type: Type.OBJECT,
                          properties: {
                            type: { type: Type.STRING },
                            table: { type: Type.STRING },
                            condition: { type: Type.STRING }
                          },
                          required: ["type", "table", "condition"]
                        } 
                      },
                      conditions: { type: Type.ARRAY, items: { type: Type.STRING } },
                      groupBy: { type: Type.ARRAY, items: { type: Type.STRING } },
                      orderBy: { type: Type.ARRAY, items: { type: Type.STRING } },
                    },
                    required: ["columns", "sources", "joins", "conditions"]
                  }
                },
                required: ["id", "label", "type", "sqlSnippet", "explanation", "ast"]
              }
            }
          },
          required: ["nodes"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as AnalysisResult;

  } catch (error) {
    console.error("Gemini Analysis Failed:", error);
    throw error;
  }
};

